/* ============================================================================
   Open Beatz · VIP Shuttle Leitstelle
   Eine App, zwei Ansichten: Fahrer (Handy) + Leitstelle/Dispo (PC).
   Geteilte Daten über window.storage (shared) -> alle Geräte synchron.
============================================================================ */

/* ---------------------------- Open Beatz Logo ---------------------------- *
 * Offizielle Markenassets (mit Freigabe verwendet). Icon = freigestellte
 * Wort-Bild-Marke (Sound-Kreis/Play-Button), Horiz = Logo mit Schriftzug.
 * Beide als Data-URI eingebettet, damit das Artifact ohne externes Hosting
 * auskommt. Auf dunklem Grund wird mit CSS filter:invert(1) auf Weiß gedreht
 * (Quelle ist ein schwarzes Logo auf transparentem Hintergrund).
 * ------------------------------------------------------------------------ */
const OB_ICON = "data:image/png;base64,";
const OB_HORIZ = "data:image/png;base64,";
// Auf dunklem Untergrund: invert(1) macht aus Schwarz Weiß, Transparenz bleibt erhalten.
const obInvert = { filter: "invert(1)" };
// Stimmungsbild Caldera-Bühne (mit Freigabe) für den Login-Hintergrund.
const OB_BG = "data:image/jpeg;base64,";

const PIN = "1234";
const SHARED = true;
// Storage-Abstraktion: sget/sset kapseln die Persistenz. Für den Produktivbetrieb
// (Vercel + Fahrer-Handys) wird diese Ebene gegen den Supabase-Adapter getauscht
// (siehe mitgelieferte supabase-schema.sql und supabaseStore.js). Nur hier ändern.
const SETUP_KEY = "obf:setup:v5";
const DYN_KEY = "obf:dyn:v5";
const POLL_MS = 3000;

/* ----------------------------- Storage-Helfer ---------------------------- */
const mem = {}; // Fallback, falls window.storage fehlt (nur zur Vorschau)
const hasStore = typeof window !== "undefined" && window.storage;
// Produktivbetrieb: main.jsx (im Vite-Projekt) legt den Supabase-Client unter
// window.__obfSupabase ab, falls VITE_SUPABASE_URL/ANON_KEY gesetzt sind. Im
// Chat-Artifact existiert dieser Wert nicht -> automatischer Rückfall auf
// window.storage. Dieselbe Datei läuft also unverändert in beiden Umgebungen.
// Als Funktion, nicht als eingefrorene Konstante: main.jsx setzt window.__obfSupabase
// erst NACHDEM dieses Modul (per import) schon geladen wurde — eine Konstante hier
// würde also immer "nicht verbunden" einfrieren, selbst wenn Supabase kurz danach
// bereitsteht. Bei jedem Aufruf frisch prüfen behebt das zuverlässig.
const hasSupabase = () => typeof window !== "undefined" && !!window.__obfSupabase;
// Optionaler Shared-Secret-Header für api/chat.js und api/send-push.js
// (siehe Nachtrag 3 in supabase-schema.sql / BACKEND-README). Kein echtes
// Geheimnis, landet zwangsläufig im ausgelieferten JS-Bundle — soll nur
// automatisiertes/versehentliches Fremdnutzen der Endpunkte erschweren,
// nicht einen gezielten Angreifer aufhalten.
function apiHeaders() {
  const h = { "Content-Type": "application/json" };
  const secret = typeof import.meta !== "undefined" ? import.meta.env?.VITE_INTERNAL_API_SECRET : undefined;
  if (secret) h["x-app-secret"] = secret;
  return h;
}

/* ------------------------------ Google Maps ------------------------------ *
 * Optionale echte Kartenansicht (Live-Fahrer-GPS) zusätzlich zur kostenlosen
 * Schema-Karte, siehe LiveGoogleMap weiter unten. Bewusst NICHT automatisch
 * geladen: das Google-Skript wird erst angefordert, wenn die Leitstelle aktiv
 * auf die Google-Maps-Ansicht wechselt (Toggle in MapTab), und
 * danach nur EIN EINZIGES Mal pro Browser-Sitzung (google.maps.Map wird nicht
 * bei jedem 3s-Poll neu erzeugt, nur die Marker-Positionen werden aktualisiert).
 * Das hält den Verbrauch weit im kostenlosen Google-Kontingent (aktuell rund
 * 10.000 "Map Loads"/Monat pro SKU, Stand 2026 nach Wegfall des früheren
 * $200-Pauschalguthabens). Der Key ist ein Browser-Key (in der Google Cloud
 * Console per HTTP-Referrer auf die eigene Domain eingeschränkt), kein
 * Server-Secret wie der Supabase-Service-Role-Key.
 */
const hasGoogleMaps = () => typeof import.meta !== "undefined" && !!import.meta.env?.VITE_GOOGLE_MAPS_API_KEY;
let googleMapsLoadPromise = null;
function loadGoogleMapsApi() {
  if (typeof window !== "undefined" && window.google?.maps) return Promise.resolve(window.google.maps);
  if (googleMapsLoadPromise) return googleMapsLoadPromise;
  googleMapsLoadPromise = new Promise((resolve, reject) => {
    const key = typeof import.meta !== "undefined" ? import.meta.env?.VITE_GOOGLE_MAPS_API_KEY : undefined;
    if (!key) { googleMapsLoadPromise = null; reject(new Error("Kein Google-Maps-Key hinterlegt (VITE_GOOGLE_MAPS_API_KEY).")); return; }
    const script = document.createElement("script");
    // WICHTIG: kein "loading=async" hier. Mit dem Flag lädt Google das
    // Bootstrap-Skript sofort, aber die eigentlichen Klassen (Map, Marker, ...)
    // erst asynchron nach ("dynamic library import") - beim script.onload
    // unten wäre google.maps.Map dann noch undefined -> "undefined is not a
    // constructor". Ohne das Flag lädt alles synchron und ist bei onload
    // vollständig da, wie der restliche Code hier es erwartet.
    script.src = `https://maps.googleapis.com/maps/api/js?key=${encodeURIComponent(key)}&v=weekly`;
    script.async = true;
    script.onerror = () => { googleMapsLoadPromise = null; reject(new Error("Google Maps konnte nicht geladen werden (Netzwerk/Key prüfen).")); };
    script.onload = () => resolve(window.google.maps);
    document.head.appendChild(script);
  });
  return googleMapsLoadPromise;
}

const fromDbDriver = (d) => ({
  id: d.id, firstName: d.first_name, lastName: d.last_name, vehicleType: d.vehicle_type,
  vehicleId: d.vehicle_id, seats: d.seats, active: d.active,
  phone: d.phone || "", plate: d.plate || "", pin: d.pin || "",
});
const toDbDriver = (d) => ({
  id: d.id, first_name: d.firstName, last_name: d.lastName, vehicle_type: d.vehicleType,
  vehicle_id: d.vehicleId, seats: d.seats, active: d.active !== false,
  phone: d.phone || "", plate: d.plate || "", pin: d.pin || "",
});

async function sbGetSetup() {
  const sb = window.__obfSupabase;
  const [settingsRes, driversRes] = await Promise.all([
    sb.from("settings").select("*").eq("id", 1).single(),
    sb.from("drivers").select("*"),
  ]);
  // PGRST116 = "keine Zeile gefunden" bei .single() -> das ist ein legitimer
  // Fall (z. B. Schema gerade erst angelegt), kein Ladefehler. Jeder andere
  // Fehler (Netzwerk, RLS, Timeout, ...) muss als echter Fehler durchgereicht
  // werden statt hier still zu "keine Daten" zu werden (siehe sget unten).
  if (settingsRes.error && settingsRes.error.code !== "PGRST116") {
    throw new Error("Supabase-Ladefehler (settings): " + settingsRes.error.message);
  }
  if (driversRes.error) {
    throw new Error("Supabase-Ladefehler (drivers): " + driversRes.error.message);
  }
  const row = settingsRes.data;
  if (!row) return null;
  return {
    drivers: (driversRes.data || []).map(fromDbDriver),
    dispatchers: row.dispatchers || [],
    locations: row.locations || [],
    matrix: row.matrix || {},
    zones: row.zones || ZONES,
    config: row.config || {},
    // Wird nicht mehr generell mitgeladen (ging vorher an jede Rolle raus,
    // Fahrer/Stage inklusive) — siehe loadGuestTokens() für die Leitstelle
    // und guest_session()-RPC für den Gast-Link selbst.
    guestTokens: [],
    rev: row.setup_rev || 0,
  };
}
// Schreibt settings/drivers nur noch über geprüfte RPCs (siehe
// supabase-schema.sql), nicht mehr per offenem Tabellenzugriff.
// baseRev wird für ein atomares Compare-and-Swap in der DB gebraucht:
// schlägt es fehl (jemand anders hat zwischenzeitlich geschrieben), kommt
// { ok:false, value: <aktueller Serverstand> } zurück statt zu überschreiben.
// Settings UND Fahrer werden seit Paket 1 in EINER Transaktion geschrieben
// (write_setup_and_drivers_if_unchanged): entweder beides oder nichts. Vorher
// waren das zwei getrennte RPC-Aufrufe nacheinander, was bei Fehler im zweiten
// Schritt einen inkonsistenten Zwischenzustand hinterlassen konnte.
async function sbSetSetup(val, baseRev) {
  const sb = window.__obfSupabase;
  // EIN atomarer Aufruf statt vorher zwei (settings-CAS, dann separat drivers):
  // write_setup_and_drivers_if_unchanged schreibt beides in derselben
  // Postgres-Transaktion. Scheitert der Fahrer-Teil, wird der Settings-Teil
  // automatisch mitzurückgerollt -> kein inkonsistenter Zwischenzustand mehr.
  // p_has_drivers bildet exakt das bisherige Verhalten ab:
  //   Array.isArray(val.drivers) -> true (auch [] wird geschrieben, damit sich
  //     alle Fahrer auf einmal entfernen lassen),
  //   undefined/null (Aufruf ohne Fahrer-Änderung) -> false, Tabelle
  //     unangetastet.
  const hasDrivers = Array.isArray(val.drivers);
  const { data, error } = await sb.rpc("write_setup_and_drivers_if_unchanged", {
    p_expected_rev: baseRev ?? 0,
    p_dispatchers: val.dispatchers || [],
    p_locations: val.locations || [],
    p_matrix: val.matrix || {},
    p_zones: val.zones || [],
    p_config: val.config || {},
    p_drivers: hasDrivers ? val.drivers.map(toDbDriver) : [],
    p_has_drivers: hasDrivers,
  });
  if (error) throw error;
  const row = Array.isArray(data) ? data[0] : data;
  if (!row) return { ok: false, value: null };
  // Fahrer nach dem Speichern frisch laden. Fehler hier NICHT verschlucken:
  // vorher wurde nur "data" destrukturiert, ein Ladefehler (Netzwerk, RLS,
  // Timeout) fiel dann auf (drivers || []) zurück und hätte eine LEERE
  // Fahrerliste in den App-State geschrieben, obwohl in der DB alle Fahrer
  // noch da sind. Der eigentliche Schreibvorgang war zu diesem Zeitpunkt schon
  // erfolgreich (die kombinierte RPC ist atomar durchgelaufen), nur das
  // Wieder-Einlesen scheitert. Deshalb werfen wir und lassen den Aufrufer
  // (updateSetup) das als Fehler behandeln, statt eine falsche leere Liste
  // anzuzeigen.
  const { data: drivers, error: driversReloadError } = await sb.from("drivers").select("*");
  if (driversReloadError) {
    throw new Error("Fahrer nach dem Speichern nicht neu ladbar: " + driversReloadError.message);
  }
  return {
    ok: row.ok,
    value: {
      dispatchers: row.dispatchers || [], locations: row.locations || [], matrix: row.matrix || {},
      zones: row.zones || [], config: row.config || {}, rev: row.rev,
      drivers: (drivers || []).map(fromDbDriver), guestTokens: [],
    },
  };
}
// Für die Leitstellen-Ansicht (Gast-/Artist-Links-Settings): läuft separat
// von updateSetup, weil Gast-Token nicht mehr Teil des generellen setup-
// Objekts sind (siehe sbGetSetup oben).
async function loadGuestTokens() {
  const sb = window.__obfSupabase;
  const { data, error } = await sb.rpc("dispatcher_list_guest_tokens");
  if (error) throw error;
  return (data || []).map((t) => ({ token: t.token, djName: t.dj_name, createdAt: new Date(t.created_at).getTime() }));
}
async function saveGuestTokens(tokens) {
  const sb = window.__obfSupabase;
  const { error } = await sb.rpc("dispatcher_save_guest_tokens", {
    p_tokens: tokens.map((t) => ({ token: t.token, dj_name: t.djName })),
  });
  if (error) throw error;
}
/* -------- Zentrale Zugriffsschicht für dyn_data (Paket 2, Teil 5) ---------- *
 * EINE Quelle der Wahrheit für die Top-Level-Felder von dyn_data. Bisher stand
 * die Feldliste an fünf Stellen wörtlich (Default-Objekt an drei Orten, Lesen aus
 * dyn_data, Lesen aus der RPC-Rückgabe) plus die camelCase<->snake_case-Übersetzung
 * fürs RPC an zweien. Ein neues Feld musste man überall gleichzeitig ergänzen.
 *
 * WICHTIG: Die SQL-Funktion write_dyn_if_unchanged baut dyn_data per
 * jsonb_build_object KOMPLETT aus genau diesen Feldern neu (siehe
 * supabase-schema.sql). Ein neues Feld hier UND in der SQL-Signatur ergänzen,
 * sonst geht es beim nächsten Schreiben still verloren (genau der Bug aus Commit
 * da31fa8, der artistPresence/messages gelöscht hätte). assertKnownDynKeys()
 * unten macht dieses Vergessen an der Schreibstelle laut, statt still zu löschen.
 *
 * rev ist bewusst NICHT Teil von DYN_FIELDS: es wird separat gehandhabt
 * (p_expected_rev rein, dyn_rev von der DB hochgezählt), nie als Datenfeld
 * übergeben.
 * Defaults per Factory (() => [] / () => ({})), damit jeder Aufruf frische
 * Referenzen bekommt, nie ein geteiltes Array/Objekt.                          */
const DYN_FIELDS = [
  { key: "rides",           db: "rides",            empty: () => [] },
  { key: "driverState",     db: "driver_state",     empty: () => ({}) },
  { key: "dispatcherState", db: "dispatcher_state", empty: () => ({}) },
  { key: "artistPresence",  db: "artist_presence",  empty: () => ({}) },
  { key: "messages",        db: "messages",         empty: () => [] },
];
// Leeres dyn-Objekt (rev default 0). Optionale Overrides, z. B. emptyDyn({ rides: seed }).
function emptyDyn(overrides) {
  const out = { rev: 0 };
  for (const f of DYN_FIELDS) out[f.key] = f.empty();
  return overrides ? { ...out, ...overrides } : out;
}
// Aus dem gespeicherten dyn_data-JSON (camelCase) normalisieren, mit Defaults.
// Bildet exakt das bisherige "d.feld || default" ab (|| greift bei null/undefined;
// gespeicherte [] / {} sind truthy und bleiben erhalten).
function dynFromData(data, revRaw) {
  const src = data || {};
  const out = { rev: revRaw || 0 };
  for (const f of DYN_FIELDS) out[f.key] = src[f.key] || f.empty();
  return out;
}
// Aus der RPC-Rückgabe (snake_case) normalisieren. rev wird 1:1 übernommen
// (kein || 0 — die RPC liefert immer eine Zahl, wie bisher).
function dynFromRpcRow(row) {
  const out = { rev: row.rev };
  for (const f of DYN_FIELDS) out[f.key] = row[f.db] || f.empty();
  return out;
}
// p_*-Parameterobjekt für write_dyn_if_unchanged (rev NICHT enthalten, siehe oben).
function dynToRpcParams(val) {
  const p = {};
  for (const f of DYN_FIELDS) p["p_" + f.db] = val[f.key] || f.empty();
  return p;
}
// Sicherheitsnetz gegen den da31fa8-Bug: ein Top-Level-Feld in dyn, das NICHT in
// DYN_FIELDS steht, wird von write_dyn_if_unchanged still verworfen. Statt
// stillem Datenverlust hier eine laute Fehlermeldung an der Schreibstelle.
const KNOWN_DYN_KEYS = new Set([...DYN_FIELDS.map((f) => f.key), "rev"]);
function assertKnownDynKeys(val) {
  const unknown = Object.keys(val || {}).filter((k) => !KNOWN_DYN_KEYS.has(k));
  if (unknown.length) {
    console.error(
      "dyn_data enthält unbekannte Top-Level-Felder, die write_dyn_if_unchanged NICHT speichert " +
      "(in DYN_FIELDS UND die SQL-Signatur ergänzen, sonst gehen sie still verloren): " +
      unknown.join(", ")
    );
  }
}

async function sbGetDyn() {
  const sb = window.__obfSupabase;
  const { data: row, error } = await sb.from("settings").select("dyn_data, dyn_rev").eq("id", 1).single();
  // Siehe sbGetSetup: PGRST116 (keine Zeile) ist legitim, alles andere ein
  // echter Ladefehler, der nicht als "keine Daten" durchgehen darf.
  if (error && error.code !== "PGRST116") {
    throw new Error("Supabase-Ladefehler (dyn_data): " + error.message);
  }
  if (!row) return null;
  return dynFromData(row.dyn_data, row.dyn_rev);
}
// Atomares Compare-and-Swap statt blindem Überschreiben (siehe
// write_dyn_if_unchanged in supabase-schema.sql, Nachtrag 3). baseRev ist
// die Revision, auf der die App ihre Änderung berechnet hat; weicht sie in
// der DB inzwischen ab, kommt der aktuelle Serverstand zurück statt dass
// die Änderung durchgeschrieben wird.
async function sbSetDyn(val, baseRev) {
  const sb = window.__obfSupabase;
  // Guard direkt an der Schreibstelle: würde val ein Top-Level-Feld enthalten,
  // das nicht in DYN_FIELDS/der SQL-Signatur steht, verwirft es die RPC still.
  assertKnownDynKeys(val);
  const { data, error } = await sb.rpc("write_dyn_if_unchanged", {
    p_expected_rev: baseRev ?? 0,
    ...dynToRpcParams(val),
  });
  if (error) throw error;
  const row = Array.isArray(data) ? data[0] : data;
  if (!row) return { ok: false, value: null };
  return { ok: row.ok, value: dynFromRpcRow(row) };
}

/* -------- Fahrer-GPS in eigener Tabelle (Paket 2, Teil 3) ----------------- *
 * Eigener Schreib-/Lesepfad, der dyn_rev NICHT anfasst — damit lösen GPS-Pings
 * keine Revisionskonflikte mit gleichzeitigen Dispo-Aktionen mehr aus (siehe
 * Nachtrag 7 in supabase-schema.sql). Nur der Supabase-Pfad nutzt das; im
 * Chat-Artifact (window.storage) bleibt GPS wie bisher in
 * dyn_data.driverState[id].gps (kein separater Speicher dort verfügbar).       */
// Schreiben: ein Upsert pro Fahrer über die dedizierte RPC. Wirft bei echtem
// Fehler (wie die anderen sb*-Helfer). Der Aufrufer (useDriverLocationSharing)
// behandelt das best-effort — ein fehlgeschlagener Ping wird beim nächsten
// (spätestens in 45s) erneut versucht, ohne die App zu stören.
async function sbWriteDriverLocation(driverId, fix) {
  const sb = window.__obfSupabase;
  const { error } = await sb.rpc("upsert_driver_location", {
    p_driver_id: driverId,
    p_lat: fix.lat,
    p_lng: fix.lng,
    p_accuracy: fix.accuracy ?? null,
    p_heading: fix.heading ?? null,
    p_speed: fix.speed ?? null,
  });
  if (error) throw error;
}
// Lesen: alle Fahrer-Positionen als Map { driverId: { lat, lng, accuracy, at } }.
// updated_at (timestamptz) wird auf epoch-ms `at` normalisiert, damit die Form
// exakt der bisherigen dyn_data.driverState[id].gps entspricht und die drei
// Lesestellen unverändert bleiben können. Wirft bei echtem Ladefehler.
async function sbGetDriverLocations() {
  const sb = window.__obfSupabase;
  const { data, error } = await sb.from("driver_locations").select("driver_id, latitude, longitude, accuracy, updated_at");
  if (error) throw error;
  const out = {};
  (data || []).forEach((r) => {
    out[r.driver_id] = {
      lat: r.latitude, lng: r.longitude,
      accuracy: r.accuracy ?? null,
      at: r.updated_at ? new Date(r.updated_at).getTime() : 0,
    };
  });
  return out;
}
// Reine Merge-Logik (unit-testbar, siehe /tmp-Node-Test): fügt die Positionen
// aus der neuen Tabelle in eine Kopie von driverState[id].gps ein. Pro Fahrer
// gewinnt die FRISCHERE Quelle (größeres `at`) — so ist die Übergangsphase in
// beide Richtungen sauber: ein Fahrer auf altem Frontend schreibt weiter nach
// dyn (bleibt erhalten), einer auf neuem in die Tabelle (wird bevorzugt, sobald
// aktueller). Fasst nur das gps-Feld an, alles andere in driverState bleibt
// unverändert. Gibt eine NEUE driverState-Referenz nur zurück, wenn sich real
// etwas ändert, sonst das Original (spart unnötige Re-Renders).
function mergeDriverLocations(driverState, locs) {
  if (!locs || Object.keys(locs).length === 0) return driverState || {};
  const base = driverState || {};
  let changed = false;
  const out = { ...base };
  for (const id of Object.keys(locs)) {
    const loc = locs[id];
    if (!loc || loc.lat == null || loc.lng == null) continue;
    const cur = base[id] && base[id].gps;
    // vorhandene dyn-Position gewinnt nur, wenn sie echt frischer ist
    if (cur && cur.at != null && loc.at != null && cur.at >= loc.at) continue;
    out[id] = { ...(base[id] || {}), gps: { lat: loc.lat, lng: loc.lng, accuracy: loc.accuracy ?? null, at: loc.at } };
    changed = true;
  }
  return changed ? out : base;
}

async function sget(key) {
  // WICHTIG: der Supabase-Pfad bewusst NICHT in dieses try/catch einschließen.
  // sbGetSetup/sbGetDyn werfen bei einem echten Ladefehler (Netzwerk, RLS,
  // Timeout, ...) jetzt selbst ("throw new Error(...)"), das muss bis zum
  // Aufrufer durchgereicht werden — sonst sieht ein Ladefehler für die App
  // identisch aus wie "es gibt einfach noch keine Daten", und sie zeigt sich
  // im schlimmsten Fall leer statt einen Fehler zu melden.
  if (hasSupabase()) return key === SETUP_KEY ? await sbGetSetup() : await sbGetDyn();
  try {
    if (!hasStore) return mem[key] ? JSON.parse(mem[key]) : null;
    const r = await window.storage.get(key, SHARED);
    return r ? JSON.parse(r.value) : null;
  } catch { return null; } // window.storage: fehlender Key wirft laut API, das ist hier der Normalfall "keine Daten"
}
// Rückgabe jetzt { ok, value } statt boolean: bei Supabase ist "ok" das
// Ergebnis eines echten atomaren Compare-and-Swap in der DB (siehe
// sbSetDyn/sbSetSetup), "value" bei ok:false der aktuelle Serverstand, auf
// den die App ihre Änderung erneut anwenden kann. Im Chat-Artifact
// (window.storage) gibt es kein serverseitiges CAS, dort bleibt es beim
// bisherigen Best-Effort-Schreiben (ok:true, value: val), unverändert
// dokumentiert als "last write wins" in der Storage-API.
// WICHTIG: Für Supabase NICHT try/catch um sbSetSetup/sbSetDyn legen. Beide
// werfen bei einem ECHTEN Fehler (RPC-Problem, Netzwerk, Berechtigung) schon
// selbst ("if (error) throw error"), das muss hier durchgereicht werden statt
// in {ok:false} umgewandelt zu werden — sonst sieht das für updateDyn/
// updateSetup IDENTISCH aus wie ein normaler, erwarteter Kollisionsfall
// (jemand anderes hat gerade geschrieben). Die Folge wäre: bis zu 6 sinnlose
// Wiederholversuche, dann stilles Aufgeben, ohne dass die aufrufende Stelle
// (z. B. "Push aktivieren") je erfährt, dass der Schreibvorgang nie geklappt
// hat — genau das hat einen echten Bug verursacht (Push zeigte "aktiv", war
// aber nie in der DB gespeichert). Im Chat-Artifact (window.storage) bleibt
// es beim bisherigen Best-Effort, dort gibt es diese Unterscheidung nicht.
async function sset(key, val, baseRev) {
  if (hasSupabase()) {
    return key === SETUP_KEY ? await sbSetSetup(val, baseRev) : await sbSetDyn(val, baseRev);
  }
  try {
    const s = JSON.stringify(val);
    if (!hasStore) { mem[key] = s; return { ok: true, value: val }; }
    await window.storage.set(key, s, SHARED);
    return { ok: true, value: val };
  } catch (e) { console.error("storage.set (window.storage)", e); return { ok: false, value: null }; }
}

// Login-Status pro Gerät (NICHT geteilt) — bewusst echtes localStorage statt des
// obigen window.storage: funktioniert identisch im Artifact und nach dem echten
// Deploy, und ist an genau dieses Gerät/diesen Browser gebunden, nicht an einen
// Claude-Account. So bleibt z. B. ein Fahrer-Handy dauerhaft eingeloggt, auch
// wenn der Tab vom Betriebssystem beendet und neu geladen wird.
const SESSION_KEY = "obf:session:v1";
function loadSession() {
  try { const raw = window.localStorage.getItem(SESSION_KEY); return raw ? JSON.parse(raw) : null; } catch { return null; }
}
function saveSession(session) {
  try {
    if (session) window.localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    else window.localStorage.removeItem(SESSION_KEY);
  } catch { /* z. B. privates Surfen ohne Speicherzugriff — dann bleibt es beim Vordergrund-Login */ }
}

