/* ------------------------------- Zeit-Utils ------------------------------ */
const pad = (n) => String(n).padStart(2, "0");
const toMin = (hhmm) => { const [h, m] = (hhmm || "0:0").split(":").map(Number); return h * 60 + (m || 0); };
const fromMin = (t) => `${pad(Math.floor((t % 1440) / 60))}:${pad(t % 60)}`;
const sortMin = (hhmm) => { const m = toMin(hhmm); return m < 360 ? m + 1440 : m; }; // Nacht: 00–06 h ans Ende
// Lokales Datum als ISO (YYYY-MM-DD) OHNE Zeitzonen-Verschiebung (kein toISOString auf Mitternacht)
function localDateISO(d) { return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`; }
function fmtDur(min) {
  if (min == null) return "?";
  const h = Math.floor(min / 60), m = Math.round(min % 60);
  return h ? `${h} h ${pad(m)} min` : `${m} min`;
}
function nowHM() { const d = new Date(); return `${pad(d.getHours())}:${pad(d.getMinutes())}`; }

// Erzeugt einen universellen Karten-/Navigations-Link für das Ziel einer Fahrt.
// Nutzt die Google-Maps-URL-API (https://www.google.com/maps/dir/?...): die
// leitet auf iOS wie Android an die jeweils installierte Karten-App bzw. den
// Browser weiter, ohne dass wir plattformspezifisch unterscheiden müssen.
// Bevorzugt exakte Koordinaten (lat/lng des bekannten Orts), fällt sonst auf
// die hinterlegte Adresse und zuletzt auf den Namen zurück. Für Ziele ohne
// jede dieser Angaben (reiner Custom-Text ohne Koordinaten) gibt die Funktion
// null zurück -> Aufrufer blendet den Button dann aus, statt einen kaputten
// Link anzubieten.
function navUrlForRide(setup, ride) {
  const loc = setup.locations.find((l) => l.id === ride.toId);
  let dest = null;
  if (loc && loc.lat != null && loc.lng != null) dest = `${loc.lat},${loc.lng}`;
  else if (loc && loc.address) dest = loc.address;
  else if (loc && loc.name) dest = loc.name;
  else if (ride.toCustom) dest = ride.toCustom;
  if (!dest) return null;
  return `https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(dest)}&travelmode=driving`;
}

// Misst die tatsächliche Breite eines Containers (per ResizeObserver). Wichtig in Artifacts:
// der Frame kann schmaler sein als der Bildschirm, daher sind feste Tailwind-Breakpoints
// (lg/xl/2xl, an die Fensterbreite gekoppelt) hier unzuverlässig.
// Callback-Ref statt festem ref+useEffect: misst auch dann korrekt, wenn das Element erst
// nach dem ersten Rendern erscheint (z. B. weil ein anderer Tab aktiv war).
function useElementWidth() {
  const [width, setWidth] = useState(0);
  const obsRef = useRef(null);
  const setRef = useCallback((node) => {
    if (obsRef.current) { obsRef.current.disconnect(); obsRef.current = null; }
    if (node) {
      setWidth(node.getBoundingClientRect().width);
      const ro = new ResizeObserver((entries) => { for (const e of entries) setWidth(e.contentRect.width); });
      ro.observe(node);
      obsRef.current = ro;
    }
  }, []);
  return [setRef, width];
}
const WD = ["So", "Mo", "Di", "Mi", "Do", "Fr", "Sa"];
function fmtDate(iso) {
  if (!iso) return "";
  const d = new Date(iso + "T12:00:00");
  return `${WD[d.getDay()]} ${pad(d.getDate())}.${pad(d.getMonth() + 1)}.`;
}
// Excel-Serial (Tage seit 1899-12-30) -> Date
function excelSerialToDate(n) {
  const ms = Math.round((n - 25569) * 86400 * 1000); // 25569 = Tage 1899-12-30 .. 1970-01-01
  const d = new Date(ms);
  return new Date(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate(), 12, 0, 0);
}

function travel(matrix, a, b) {
  if (!a || !b) return null;
  if (a === b) return { min: 0, km: 0 };
  return matrix[`${a}|${b}`] || matrix[`${b}|${a}`] || null;
}
// Fahrzeit in Minuten; null wenn unbekannt (z. B. eigener Ort ohne Matrix-Eintrag)
function travelMin(matrix, a, b) { const t = travel(matrix, a, b); return t ? t.min : null; }

// Punkt 6/7: effektive Dauer für Planung/Konfliktprüfung – nie 0 bei unbekannter Strecke,
// sondern die konfigurierte Mindestdauer. Anzeige bleibt separat „?" wenn null.
function effDur(config, r) { return r.estDurationMin != null ? r.estDurationMin : (config?.minDurationMin ?? 20); }

const STATUS_TS = { accepted: "acceptedAt", enroute_pickup: "enrouteAt", onboard: "onboardAt", done: "doneAt", planned: "plannedAt", cancelled: "cancelledAt" };

// Punkt 9: einheitlicher Ereignis-Verlauf pro Fahrt (Audit-Log).
function logRide(r, event, by, detail) {
  r.log = r.log || [];
  r.log.push({ event, at: Date.now(), by: by || "system", detail: detail || "" });
  r.updatedAt = Date.now();
}
// Punkt 1: Meldung gilt als offen, solange nicht „done" (rückwärtskompatibel zu resolved).
const issueOpen = (i) => (i.state ? i.state !== "done" : !i.resolved);
const rideHasOpenIssue = (r) => (r.issues || []).some(issueOpen);

// Punkt 10: Status setzen inkl. Zeitstempel, Statusverlauf und Ereignis-Log.
function setRideStatus(r, status, by) {
  const prev = r.status;
  r.status = status;
  const now = Date.now();
  if (STATUS_TS[status]) r[STATUS_TS[status]] = now;
  r.statusHistory = r.statusHistory || [];
  r.statusHistory.push({ status, at: now, by });
  logRide(r, "status", by, `${STATUS_LABEL[prev] || prev || "—"} → ${STATUS_LABEL[status] || status}`);
  r.updatedAt = now;
}

/* ------------------------ Fahrt: Klassifizierung ------------------------ */
function classify(fromId, toId, fromTxt, toTxt) {
  const isAir = (id, t) => id === "airport" || /airport|flughafen/i.test(t || "");
  const isVenue = (id, t) => id === "festival" || /venue|caldera|zone|stonelands|forest|stage|woods/i.test(t || "");
  const isHotel = (id) => ["sheraton", "moevenpick"].includes(id);
  if (isAir(fromId, fromTxt)) return "arrival";
  if (isVenue(fromId, fromTxt) && (isHotel(toId) || isAir(toId, toTxt))) return "return";
  if (isHotel(fromId) && isVenue(toId, toTxt)) return "toVenue";
  return "transfer";
}

/* ------------------------------ Festival-Tag ----------------------------- */
function festDayKey(date, time) {
  // Fahrten 00:00–05:59 gehören zur Nacht des Vortags
  if (!date) return "";
  if (toMin(time) < 360) {
    const d = new Date(date + "T12:00:00"); d.setDate(d.getDate() - 1);
    return localDateISO(d);
  }
  return date;
}
function todayISO() { return localDateISO(new Date()); }
// „Jetzt" in sortMin-Space für einen bestimmten Festival-Tag.
// heute -> echte Uhr; Vergangenheit -> alles erledigt; Zukunft -> nichts gestartet.
function dayNowMin(dayKey) {
  const d = new Date();
  const curMin = d.getHours() * 60 + d.getMinutes();
  let festToday = todayISO();
  if (curMin < 360) { const y = new Date(); y.setDate(y.getDate() - 1); festToday = localDateISO(y); }
  if (dayKey === festToday) return curMin < 360 ? curMin + 1440 : curMin;
  return dayKey < festToday ? 99999 : -99999;
}

