function StatusPill({ status }) {
  const map = {
    planned: "bg-orange-500/20 text-orange-300", accepted: "bg-blue-500/20 text-blue-300",
    enroute_pickup: "bg-orange-500/20 text-orange-300", onboard: "bg-orange-500/20 text-orange-300",
    done: "bg-emerald-500/20 text-emerald-300", cancelled: "bg-stone-700 text-stone-400",
  };
  return <span className={`text-xs px-2 py-0.5 rounded-full ${map[status] || "bg-stone-700 text-stone-400"}`}>{STATUS_LABEL[status] || status || "—"}</span>;
}

// Vier wesentliche Schritte (Check-in/out) als Fortschrittsanzeige.
const STEP_SEQ = [
  { key: "accepted", short: "Angenommen" },
  { key: "enroute_pickup", short: "Anfahrt" },
  { key: "onboard", short: "Gast an Bord" },
  { key: "done", short: "Abgesetzt" },
];
function StepProgress({ status }) {
  if (status === "cancelled") return null;
  const doneIdx = STEP_SEQ.findIndex((s) => s.key === status); // -1 wenn planned
  return (
    <div className="flex items-center gap-1 mt-3">
      {STEP_SEQ.map((s, i) => {
        const reached = i <= doneIdx;
        return (
          <div key={s.key} className="flex-1 flex flex-col items-center gap-1">
            <div className={`h-1.5 w-full rounded-full ${reached ? (status === "done" ? "bg-emerald-500" : "bg-orange-500") : "bg-stone-700"}`} />
            <span className={`text-[9px] leading-tight text-center ${reached ? "text-stone-300" : "text-stone-600"}`}>{s.short}</span>
          </div>
        );
      })}
    </div>
  );
}

/* =========================================================================
   Tage-Ableitung
========================================================================= */
function dayTabs(setup, dyn) {
  const set = new Set(setup.config.festivalDates || []);
  (dyn.rides || []).forEach((r) => r.dayKey && set.add(r.dayKey));
  const arr = [...set].filter(Boolean).sort();
  return arr.map((k) => ({ key: k, label: fmtDate(k) }));
}

/* =========================================================================
   LEITSTELLE / DISPO (PC)
========================================================================= */
/* =========================================================================
   CHAT-ASSISTENT (Leitstelle) — Fragen + vorgeschlagene Änderungen.
   Wichtig: Der Chat ändert NIE selbst Daten. Er kann nur eine von wenigen
   fest definierten, sicheren Aktionen VORSCHLAGEN (JSON, kein Freitext-Patch);
   erst ein expliziter Klick auf "Bestätigen" führt sie aus — über exakt
   dieselben Funktionen, die auch die normalen Buttons in der App nutzen.
========================================================================= */
// Kompakter Datenkontext für den gewählten Tag — bewusst ohne Telefonnummern,
// GPS, Gast-Tokens oder sonstige sensible/irrelevante Felder.
function buildChatContext(setup, dyn, day) {
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";
  const rides = (dyn.rides || []).filter((r) => r.dayKey === day && r.status !== "cancelled")
    .sort((a, b) => sortMin(a.time) - sortMin(b.time))
    .map((r) => {
      const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
      const openIssues = (r.issues || []).filter(issueOpen).map((i) => i.type);
      return {
        rideId: r.id, time: r.time, from: ln(r.fromId, r.fromCustom), to: ln(r.toId, r.toCustom),
        zone: r.zone || undefined, artist: r.djName || undefined, passengers: r.passengerCount,
        status: STATUS_LABEL[r.status] || r.status,
        driver: drv ? `${drv.firstName} ${drv.lastName} (${drv.vehicleType === "Van" ? "Van" : "Car"})` : null,
        driverId: drv ? drv.id : null,
        flight: r.flightNo ? `${r.flightNo} ${r.flightStatus || ""}`.trim() : undefined,
        issues: openIssues.length ? openIssues : undefined,
      };
    });
  const drivers = setup.drivers.map((d) => ({ driverId: d.id, name: `${d.firstName} ${d.lastName}`, vehicleId: d.vehicleId, type: d.vehicleType === "Van" ? "Van" : "Car", seats: d.seats }));
  return { day: fmtDate(day), rides, drivers };
}

const CHAT_SYSTEM_PROMPT = `Du bist ein Assistent für die Leitstelle einer VIP-Shuttle-Operation bei einem Musikfestival. Du bekommst den aktuellen Stand der Fahrten und Fahrer für einen Tag als JSON. Beantworte Fragen kurz und präzise auf Deutsch.

Wenn die Anfrage eine konkrete Änderung verlangt (Fahrer zuweisen, Uhrzeit ändern, Fahrt stornieren, Notiz hinzufügen), schlage sie über das "action"-Feld vor — ändere NIE selbst etwas, das macht die App erst nach Bestätigung durch einen Menschen.

Antworte AUSSCHLIESSLICH mit diesem JSON, keine Erklärung davor/danach, keine Markdown-Codeblöcke:
{"reply": "kurze Antwort auf Deutsch", "action": null}
oder bei einer vorgeschlagenen Änderung:
{"reply": "kurze Erklärung", "action": {"type": "assign", "rideId": "...", "driverId": "..." oder null, "summary": "eine Zeile: was würde passieren"}}

Erlaubte action-Typen:
- assign: {rideId, driverId} — driverId=null entfernt die Zuteilung
- reschedule: {rideId, time} — Format HH:MM
- cancel: {rideId}
- note: {rideId, note}

Ist eine Anfrage mehrdeutig (z. B. mehrere passende Fahrten/Fahrer) oder rein informativ, setze "action" auf null und frage im "reply" nach bzw. beantworte die Frage direkt. Erfinde nie eine rideId/driverId, die nicht im Kontext steht.`;

async function askChatAssistant(setup, dyn, day, history, userText) {
  const context = buildChatContext(setup, dyn, day);
  const messages = [
    ...history.slice(-6).map((m) => ({ role: m.role, content: m.text })),
    { role: "user", content: `Kontext (Tag ${context.day}):\n${JSON.stringify(context)}\n\nFrage: ${userText}` },
  ];
  // Im Chat-Artifact (window.storage vorhanden, kein Supabase-Client): direkt gegen
  // die Anthropic API, wie von Claude bereitgestellt. Nach dem Deploy (hasSupabase)
  // läuft derselbe Aufruf stattdessen über /api/chat, wo der echte Schlüssel liegt.
  if (hasSupabase()) {
    const res = await fetch("/api/chat", {
      method: "POST",
      headers: apiHeaders(),
      body: JSON.stringify({ system: CHAT_SYSTEM_PROMPT, messages }),
    });
    if (!res.ok) throw new Error(`API antwortete ${res.status}`);
    return await res.json();
  }
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ model: "claude-sonnet-4-6", max_tokens: 1000, system: CHAT_SYSTEM_PROMPT, messages }),
  });
  if (!res.ok) throw new Error(`API antwortete ${res.status}`);
  const data = await res.json();
  const text = (data.content || []).map((b) => b.text || "").join("").trim();
  const clean = text.replace(/^```json\s*|^```\s*|```\s*$/g, "").trim();
  try {
    const parsed = JSON.parse(clean);
    return { reply: String(parsed.reply || "").trim() || "(keine Antwort)", action: parsed.action || null };
  } catch {
    return { reply: text || "(keine Antwort)", action: null }; // Fallback: Rohtext anzeigen statt Fehler
  }
}

// Führt eine bestätigte Aktion über GENAU dieselben Funktionen aus wie die
// normalen Buttons (setRideStatus/logRide/dateForNightTime/triggerPush) —
// der Chat bekommt keinen eigenen, ungeprüften Schreibweg auf die Daten.
// ASYNC und awaitet updateDyn wirklich: erst wenn der Schreibvorgang von
// updateDyn mit { ok:true } bestätigt ist, gilt die Aktion als übernommen.
// Schlägt updateDyn fehl (Konflikt nach mehreren Versuchen oder ein echter
// Supabase-/Netzwerkfehler, siehe updateDyn oben), wird das als Fehler
// zurückgegeben statt stillschweigend so zu tun, als wäre gespeichert
// worden — der Push nach erfolgreicher Zuteilung/Umplanung läuft deshalb
// ebenfalls erst NACH dem bestätigten Schreiben.
async function applyChatAction(setup, dyn, updateDyn, by, action) {
  const ride = (dyn.rides || []).find((r) => r.id === action.rideId);
  if (!ride) return { ok: false, error: "Diese Fahrt existiert nicht mehr." };

  if (action.type === "assign") {
    if (action.driverId && !setup.drivers.some((d) => d.id === action.driverId)) return { ok: false, error: "Unbekannter Fahrer." };
    const res = await updateDyn((d) => {
      const r = d.rides.find((x) => x.id === action.rideId);
      if (r) {
        logRide(r, r.assignedDriverId ? "reassigned" : "assigned", by, "Über Chat-Assistent vorgeschlagen, bestätigt");
        r.assignedDriverId = action.driverId || null;
        if (r.status !== "planned") setRideStatus(r, "planned", by); else r.updatedAt = Date.now();
      }
      return d;
    });
    if (!res.ok) return { ok: false, error: res.error || "Speichern fehlgeschlagen." };
    if (action.driverId) triggerPush(action.driverId, "Neue Fahrt zugeteilt", `${ride.time} · ${ride.djName || "Fahrt"}`, `ride-${ride.id}`);
    return { ok: true };
  }
  if (action.type === "reschedule") {
    if (!/^\d{1,2}:\d{2}$/.test(action.time || "")) return { ok: false, error: "Ungültige Uhrzeit." };
    const res = await updateDyn((d) => {
      const r = d.rides.find((x) => x.id === action.rideId);
      if (r) {
        logRide(r, "time", by, `${r.time} → ${action.time} (Chat-Assistent, bestätigt)`);
        r.date = dateForNightTime(ride.dayKey, action.time);
        r.time = action.time;
        r.updatedAt = Date.now();
      }
      return d;
    });
    if (!res.ok) return { ok: false, error: res.error || "Speichern fehlgeschlagen." };
    if (ride.assignedDriverId) triggerPush(ride.assignedDriverId, "Fahrt geändert", `${ride.djName || "Fahrt"} · neue Zeit ${action.time}`, `ride-${ride.id}`);
    return { ok: true };
  }
  if (action.type === "cancel") {
    const res = await updateDyn((d) => { const r = d.rides.find((x) => x.id === action.rideId); if (r) setRideStatus(r, "cancelled", by); return d; });
    if (!res.ok) return { ok: false, error: res.error || "Speichern fehlgeschlagen." };
    return { ok: true };
  }
  if (action.type === "note") {
    const note = String(action.note || "").slice(0, 300);
    const res = await updateDyn((d) => { const r = d.rides.find((x) => x.id === action.rideId); if (r) { logRide(r, "route", by, "Notiz über Chat-Assistent ergänzt"); r.notes = note; r.updatedAt = Date.now(); } return d; });
    if (!res.ok) return { ok: false, error: res.error || "Speichern fehlgeschlagen." };
    return { ok: true };
  }
  return { ok: false, error: "Unbekannter Aktionstyp." };
}

function ChatPanel({ setup, dyn, day, updateDyn, by, liftOffset }) {
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState([]); // {role:'user'|'assistant', text, action?, resolved?}
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");
  const scrollRef = useRef(null);
  useEffect(() => { if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight; }, [messages, open]);

  const send = async () => {
    const text = input.trim();
    if (!text || busy) return;
    setInput(""); setErr("");
    const userMsg = { role: "user", text };
    setMessages((m) => [...m, userMsg]);
    setBusy(true);
    try {
      // WICHTIG: hier die bisherige Historie OHNE die gerade getippte Frage übergeben —
      // askChatAssistant hängt sie selbst (mit frischem Kontext) als letzte User-Nachricht
      // an. Würde man sie hier zusätzlich mitschicken, entstünden zwei aufeinanderfolgende
      // User-Nachrichten, was die API mit einem Fehler ablehnt.
      const res = await askChatAssistant(setup, dyn, day, messages, text);
      setMessages((m) => [...m, { role: "assistant", text: res.reply, action: res.action, resolved: false }]);
    } catch (e) {
      setErr("Chat-Assistent gerade nicht erreichbar (nur im Live-Deployment mit Netzzugriff verfügbar).");
    } finally { setBusy(false); }
  };

  // ASYNC: awaitet applyChatAction wirklich, statt sofort "Übernommen" zu
  // zeigen. Zwischenzeitlich "saving" (Buttons ausgeblendet, kleiner
  // Spinner statt Bestätigen/Verwerfen), damit nicht doppelt geklickt werden
  // kann während der Schreibvorgang noch läuft.
  const confirmAction = async (idx) => {
    setMessages((m) => m.map((x, i) => i === idx ? { ...x, resolved: "saving" } : x));
    const msg = messages[idx];
    const result = await applyChatAction(setup, dyn, updateDyn, by, msg.action);
    setMessages((m) => m.map((x, i) => i === idx ? { ...x, resolved: result.ok ? "done" : "error", resolveError: result.error } : x));
  };
  const dismissAction = (idx) => setMessages((m) => m.map((x, i) => i === idx ? { ...x, resolved: "dismissed" } : x));

  return (
    <>
      <button onClick={() => setOpen((o) => !o)} title="Chat-Assistent"
        style={{ bottom: `calc(1.25rem + ${liftOffset || "0px"})` }}
        className="fixed right-5 z-50 w-12 h-12 rounded-full bg-orange-600 hover:bg-orange-500 text-white shadow-lg flex items-center justify-center">
        {open ? <X className="w-5 h-5" /> : <MessageSquare className="w-5 h-5" />}
      </button>

      {open && (
        <div style={{ bottom: `calc(5rem + ${liftOffset || "0px"})` }}
          className="fixed right-5 z-50 w-[22rem] max-w-[calc(100vw-2.5rem)] h-[28rem] max-h-[calc(100vh-8rem)] bg-stone-900 border border-stone-800 rounded-2xl shadow-2xl flex flex-col overflow-hidden">
          <div className="px-3.5 py-2.5 border-b border-stone-800 flex items-center gap-2">
            <MessageSquare className="w-4 h-4 text-orange-400" />
            <span className="text-sm font-medium text-stone-100">Chat-Assistent</span>
            <span className="text-[10px] text-stone-500 ml-auto">nur heutiger Tag · Änderungen erst nach Bestätigung</span>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-3 space-y-2.5">
            {messages.length === 0 && (
              <div className="text-xs text-stone-500 text-center py-6">
                Frag z. B. „Wer ist gerade frei?" oder „Weise Finn die 14-Uhr-Fahrt zu".
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={m.role === "user" ? "flex justify-end" : "flex justify-start"}>
                <div className={`max-w-[85%] rounded-xl px-3 py-2 text-sm ${m.role === "user" ? "bg-orange-600 text-white" : "bg-stone-800 text-stone-100"}`}>
                  <div className="whitespace-pre-wrap">{m.text}</div>
                  {m.action && (
                    <div className="mt-2 pt-2 border-t border-white/15">
                      <div className="text-xs opacity-90 mb-1.5">{m.action.summary || "Änderung vorschlagen"}</div>
                      {!m.resolved && (
                        <div className="flex gap-1.5">
                          <button onClick={() => confirmAction(i)} className="text-xs bg-emerald-600 hover:bg-emerald-500 text-white px-2.5 py-1 rounded-lg flex items-center gap-1"><Check className="w-3 h-3" />Bestätigen</button>
                          <button onClick={() => dismissAction(i)} className="text-xs bg-stone-700 hover:bg-stone-600 text-stone-200 px-2.5 py-1 rounded-lg">Verwerfen</button>
                        </div>
                      )}
                      {m.resolved === "saving" && <div className="text-xs text-stone-400 flex items-center gap-1"><RefreshCw className="w-3 h-3 animate-spin" />wird gespeichert…</div>}
                      {m.resolved === "done" && <div className="text-xs text-emerald-300 flex items-center gap-1"><Check className="w-3 h-3" />Übernommen</div>}
                      {m.resolved === "dismissed" && <div className="text-xs text-stone-400">Verworfen</div>}
                      {m.resolved === "error" && (
                        <div className="space-y-1">
                          <div className="text-xs text-red-300">Fehler, nicht gespeichert: {m.resolveError}</div>
                          <button onClick={() => confirmAction(i)} className="text-xs bg-stone-700 hover:bg-stone-600 text-stone-200 px-2.5 py-1 rounded-lg flex items-center gap-1"><RefreshCw className="w-3 h-3" />Erneut versuchen</button>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            ))}
            {busy && <div className="text-xs text-stone-500 flex items-center gap-1.5"><RefreshCw className="w-3 h-3 animate-spin" />denkt nach…</div>}
            {err && <div className="text-xs text-orange-300">{err}</div>}
          </div>

          <div className="p-2.5 border-t border-stone-800 flex gap-1.5">
            <input value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => e.key === "Enter" && send()}
              placeholder="Frage stellen…" disabled={busy}
              className="flex-1 bg-stone-950 border border-stone-800 rounded-lg px-2.5 py-2 text-sm text-stone-200 placeholder-stone-600 focus:outline-none focus:border-orange-500" />
            <button onClick={send} disabled={busy || !input.trim()} className="shrink-0 bg-orange-600 hover:bg-orange-500 disabled:opacity-40 text-white px-3 rounded-lg"><ArrowRight className="w-4 h-4" /></button>
          </div>
        </div>
      )}
    </>
  );
}

