/* ------------------------------ Zuteilen-Modal --------------------------- */
function AssignModal({ setup, dyn, ride, onClose, onAssign }) {
  const suggestions = useMemo(() => suggestDrivers(setup, dyn, ride), [setup, dyn, ride]);
  const locName = (id, txt) => setup.locations.find((l) => l.id === id)?.short || txt || "—";
  const current = setup.drivers.find((d) => d.id === ride.assignedDriverId);
  const [assigning, setAssigning] = useState(false); // Doppelklick-Schutz + Ladezustand
  const [assignErr, setAssignErr] = useState("");     // sichtbare Meldung, falls die Zuteilung nicht gespeichert wird

  // Alle Zuteilungs-Wege (Vorschlag, manuell, entfernen) laufen hier durch:
  // sperrt gegen Doppelklick, awaitet das Ergebnis, zeigt bei echtem Fehler eine
  // Meldung statt das Modal kommentarlos zu schliessen (Parent schliesst nur bei ok).
  const doAssign = async (driverId) => {
    if (assigning) return;
    // Slice 4: Rueckfrage, wenn Wechsel/Entfernen den Live-Status einer schon
    // laufenden Fahrt still auf "Geplant" zuruecksetzen wuerde (destruktiv).
    if (wouldResetLiveStatus(ride.status, ride.assignedDriverId, driverId)) {
      const verb = driverId ? "Fahrerwechsel" : "Zuteilung entfernen";
      if (!window.confirm(`Diese Fahrt läuft schon (Status: ${STATUS_LABEL[ride.status] || ride.status}).\n\n${verb} setzt sie zurück auf „Geplant“ und verwirft den aktuellen Stand. Trotzdem?`)) return;
    }
    setAssignErr("");
    setAssigning(true);
    try {
      const res = await onAssign(driverId);
      if (res && res.ok === false && !res.cancelled) {
        setAssignErr(res.error || "Die Zuteilung konnte nicht gespeichert werden. Bitte Verbindung prüfen und erneut versuchen.");
      }
    } catch (e) {
      console.error("AssignModal.doAssign", e);
      setAssignErr("Die Zuteilung konnte nicht gespeichert werden. Bitte erneut versuchen.");
    } finally {
      setAssigning(false);
    }
  };

  return (
    <Modal onClose={onClose} title="Fahrer zuteilen" wide>
      <div className="bg-stone-950 border border-stone-800 rounded-xl p-3 mb-4 text-sm">
        <div className="flex items-center gap-3">
          <span className="font-mono text-lg">{ride.time}</span>
          <span className="text-stone-400">{locName(ride.fromId, ride.fromCustom)}</span>
          <ArrowRight className="w-4 h-4 text-stone-600" />
          <span className="text-stone-100 font-medium">{locName(ride.toId, ride.toCustom)}</span>
          {ride.zone && <span className="text-xs bg-orange-500/20 text-orange-300 px-1.5 py-0.5 rounded">{ride.zone}</span>}
          <span className="text-stone-500 flex items-center gap-1 ml-auto"><Users className="w-3.5 h-3.5" />{ride.passengerCount} Pers.</span>
        </div>
        {ride.djName && <div className="mt-1.5 text-base font-semibold text-orange-300 truncate">{ride.djName}</div>}
      </div>

      {current && (
        <div className="text-xs text-stone-500 mb-2">Aktuell zugeteilt: <span className="text-stone-300">{current.firstName} {current.lastName} ({current.vehicleType === "Van" ? "Van" : "Car"})</span></div>
      )}

      <div className="text-xs text-stone-500 mb-2 flex items-center gap-1.5"><Gauge className="w-3.5 h-3.5" />Vorschläge – Nähe &amp; Verfügbarkeit zuerst, Reisezeiten &amp; Fairness berücksichtigt</div>
      <div className="space-y-1.5 max-h-[46vh] overflow-y-auto pr-1">
        {suggestions.length === 0 && <div className="text-stone-500 text-sm py-6 text-center">Kein passender Fahrer (Kapazität/Überschneidung). Manuell unten wählen.</div>}
        {suggestions.slice(0, 8).map((x, i) => {
          const best = i === 0 && x.feasible;
          return (
            <button key={x.driver.id} onClick={() => doAssign(x.driver.id)} disabled={assigning}
              className={`w-full text-left rounded-xl px-3 py-2.5 border transition flex items-center gap-3 disabled:opacity-50 ${best ? "border-orange-500/60 bg-orange-500/10 hover:bg-orange-500/15" : x.feasible ? "border-stone-800 bg-stone-900 hover:border-stone-700" : "border-orange-500/30 bg-orange-500/5 hover:border-orange-500/50"}`}>
              <span className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-mono shrink-0 ${x.driver.vehicleType === "Van" ? "bg-orange-500/20 text-orange-300" : "bg-sky-500/20 text-sky-300"}`}>{x.driver.vehicleType === "Van" ? "Van" : "Car"}</span>
              <div className="min-w-0 flex-1">
                <div className="text-sm text-stone-100 flex items-center gap-2">
                  {x.driver.firstName} {x.driver.lastName}
                  {best && <span className="text-[10px] bg-orange-600 text-white px-1.5 py-0.5 rounded-full">beste Wahl</span>}
                  {!x.feasible && <span className="text-[10px] bg-orange-500/20 text-orange-300 px-1.5 py-0.5 rounded-full">knapp</span>}
                </div>
                <div className="text-[11px] text-stone-500">{reasonText(setup, x)}</div>
              </div>
              <ChevronRight className="w-4 h-4 text-stone-600 shrink-0" />
            </button>
          );
        })}
      </div>

      {/* Manuell */}
      <div className="mt-4 pt-3 border-t border-stone-800">
        <div className="text-xs text-stone-500 mb-2">Manuell zuweisen (alle Fahrer · mit Konfliktprüfung)</div>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-1.5 max-h-40 overflow-y-auto">
          {setup.drivers.map((d) => {
            const ev = evaluateInsertion(setup, dyn, d, ride);
            const assignManual = () => {
              if (!ev.feasible) {
                const ok = window.confirm(`${d.firstName} ${d.lastName} (${d.vehicleType === "Van" ? "Van" : "Car"}) hat einen Konflikt:\n\n• ${ev.problems.join("\n• ")}\n\nTrotzdem zuweisen?`);
                if (!ok) return;
              }
              doAssign(d.id);
            };
            return (
              <button key={d.id} onClick={assignManual} disabled={assigning}
                className={`text-xs rounded-lg px-2 py-1.5 text-left border disabled:opacity-50 ${!ev.eligible ? "bg-red-500/5 border-red-500/30" : !ev.feasible ? "bg-orange-500/5 border-orange-500/30" : "bg-stone-900 border-stone-800 hover:border-stone-600"}`}>
                <div className="text-stone-200 truncate">{d.firstName} {d.lastName[0]}.</div>
                <div className="flex items-center gap-1">
                  <span className="text-stone-500 font-mono text-[10px]">{d.vehicleType === "Van" ? "Van" : "Car"}</span>
                  {!ev.eligible ? <span className="text-[9px] text-red-400">zu klein</span>
                    : ev.overlap ? <span className="text-[9px] text-orange-400">Überschneidung</span>
                      : !ev.feasible ? <span className="text-[9px] text-orange-400">knapp</span> : null}
                </div>
              </button>
            );
          })}
        </div>
        {ride.assignedDriverId && (
          <button onClick={() => doAssign(null)} disabled={assigning} className="mt-3 text-xs text-red-400 hover:text-red-300 disabled:opacity-40 flex items-center gap-1"><X className="w-3.5 h-3.5" />Zuteilung entfernen</button>
        )}
      </div>

      {assignErr && (
        <div className="mt-4 text-sm text-red-300 bg-red-500/10 border border-red-500/25 rounded-lg px-3 py-2">{assignErr}</div>
      )}
    </Modal>
  );
}

/* ------------------------------ Fahrt-Formular --------------------------- */
function RideForm({ setup, ride, onClose, onSave, onDelete }) {
  const isNew = ride._new;
  const [saving, setSaving] = useState(false);   // Doppelklick-Schutz + Ladezustand Speichern
  const [deleting, setDeleting] = useState(false); // Doppelklick-Schutz + Ladezustand Stornieren
  const [saveErr, setSaveErr] = useState("");     // sichtbare Fehlermeldung, falls Speichern/Stornieren scheitert
  const [f, setF] = useState({
    date: ride.date || ride.dayKey || todayISO(),
    time: ride.time || "12:00",
    fromId: ride.fromId || "airport",
    toId: ride.toId || "festival",
    fromCustom: ride.fromCustom || "",
    toCustom: ride.toCustom || "",
    zone: ride.zone || "",
    djName: ride.djName || "",
    passengerCount: ride.passengerCount || 1,
    passengers: ride.passengers || "",
    flightNo: ride.flightNo || "",
    airline: ride.airline || "",
    terminal: ride.terminal || "",
    scheduledArrival: ride.scheduledArrival || "",
    actualArrival: ride.actualArrival || "",
    estimatedArrival: ride.estimatedArrival || "",
    flightStatus: ride.flightStatus || "",
    meetingPoint: ride.meetingPoint || "",
    notes: ride.notes || "",
    guestNote: ride.guestNote || "",
    onDemand: ride.onDemand || false,
  });
  const [manualDur, setManualDur] = useState(ride.estDurationMin != null ? String(ride.estDurationMin) : "");
  const [flightBusy, setFlightBusy] = useState(false);
  const [flightMsg, setFlightMsg] = useState(null);
  const set = (k, v) => setF((p) => ({ ...p, [k]: v }));
  // Telefonnummern, die im Passagiere-Text stecken (z. B. "Name (+49…)") – live,
  // aktualisiert sich beim Tippen. Nur hier sichtbar (Fahrt geöffnet), nicht in Listen.
  const contacts = useMemo(() => extractContactPhones(f.passengers), [f.passengers]);

  // Punkt 6: Flugstatus über Provider (serverseitig) abrufen; im Artifact -> Fallback.
  // Abklingzeit (FLIGHT_REFRESH_COOLDOWN_MIN) gegen das begrenzte API-Kontingent,
  // siehe Hinweis bei der Konstante. Prüft gegen f.lastFlightCheck (falls in
  // dieser Sitzung schon einmal abgefragt) ODER ride.lastFlightCheck (falls
  // beim Öffnen des Formulars schon aktuell) — je nachdem, was neuer ist.
  // "force" überspringt sie bewusst (Link unten).
  const fetchFlight = async (force) => {
    if (!f.flightNo) return;
    const baseline = { lastFlightCheck: Math.max(f.lastFlightCheck || 0, ride.lastFlightCheck || 0) };
    if (!force && flightRefreshOnCooldown(baseline)) {
      setFlightMsg({ ok: true, cooldown: true, text: `vor ${FLIGHT_REFRESH_COOLDOWN_MIN - flightCooldownRemainingMin(baseline)} Min. abgefragt · noch ${flightCooldownRemainingMin(baseline)} Min. Abklingzeit` });
      return;
    }
    setFlightBusy(true); setFlightMsg(null);
    const res = await getFlightStatus(f.flightNo, f.date);
    setFlightBusy(false);
    if (!res.ok) { setFlightMsg({ ok: false, text: res.error || "nicht verfügbar – bitte manuell pflegen" }); return; }
    setF((p) => ({
      ...p,
      airline: res.airline || p.airline,
      terminal: res.terminal || p.terminal,
      scheduledArrival: res.scheduledArrival || p.scheduledArrival,
      estimatedArrival: res.estimatedArrival || p.estimatedArrival,
      actualArrival: res.actualArrival || p.actualArrival,
      flightStatus: res.flightStatus || p.flightStatus,
      lastFlightCheck: Date.now(),
    }));
    setFlightMsg({ ok: true, text: `aktualisiert (${res.source || FLIGHT_PROVIDER})` });
  };

  const toIsFestival = f.toId === "festival";
  const dur = travel(setup.matrix, f.fromId, f.toId);        // aus Matrix (null = unbekannt)
  const durKnown = dur != null;
  const pax = Number(f.passengerCount) || 1;
  const tooBig = pax > 7; // größer als jede V-Klasse

  // Slice 3: weiche Eingabe-Warnungen (warnen, NICHT blockieren) fuer Fehler,
  // die nie gewollt sind und heute kommentarlos durchgehen. Speichern bleibt
  // immer moeglich, das sind Hinweise wie tooBig oben, keine Sperre.
  const fromCustom = f.fromId === "__custom";
  const toCustom = f.toId === "__custom";
  const sameLoc = !fromCustom && f.fromId === f.toId; // gleicher hinterlegter Ort als Start und Ziel
  const bothCustomSame = fromCustom && toCustom && f.fromCustom.trim() && f.fromCustom.trim().toLowerCase() === f.toCustom.trim().toLowerCase();
  const fromCustomEmpty = fromCustom && !f.fromCustom.trim();
  const toCustomEmpty = toCustom && !f.toCustom.trim();
  // Datums-Tippfehler (falscher Monat/Tag) erkennen: der per Nachtmodus korrekt
  // aufgeloeste Festival-Tag der Fahrt wird gegen die eingetragenen Festivaltage
  // geprueft. Nur ein Hinweis - Abhol-/Rueckfahrten am Vor-/Nachtag sind legitim
  // und bleiben erlaubt. Guard: nur wenn ueberhaupt Festivaltage hinterlegt sind.
  const festDates = setup.config.festivalDates || [];
  const effDayKey = festDayKey(f.date, f.time);
  const dateOffFestival = festDates.length > 0 && effDayKey && !festDates.includes(effDayKey);
  const inputWarnings = [];
  if (sameLoc || bothCustomSame) inputWarnings.push("Start und Ziel sind identisch. Ist das so gewollt?");
  if (fromCustomEmpty) inputWarnings.push("Für „Von“ ist „Anderer Ort“ gewählt, aber kein Ort eingetragen.");
  if (toCustomEmpty) inputWarnings.push("Für „Nach“ ist „Anderer Ort“ gewählt, aber kein Ort eingetragen.");
  if (dateOffFestival) inputWarnings.push("Dieses Datum liegt außerhalb der eingetragenen Festivaltage. Bitte Datum prüfen (Vor-/Nachtag ist ok).");

  const save = async () => {
    // Doppelklick-Schutz: laeuft schon ein Speicher-/Stornier-Vorgang, nichts tun,
    // sonst wuerde eine neue Fahrt bei schnellem Doppelklick zweimal angelegt.
    if (saving || deleting) return;
    const dayKey = festDayKey(f.date, f.time);
    const est = durKnown ? dur.min : (manualDur.trim() !== "" ? Number(manualDur) : null);
    const { _new, ...clean } = ride;
    // Punkt 4: Flug-Update-Metadaten pflegen; manuelle Änderung als Override markieren
    const flightTouched = f.flightStatus !== (ride.flightStatus || "") || f.actualArrival !== (ride.actualArrival || "") || f.estimatedArrival !== (ride.estimatedArrival || "") || f.terminal !== (ride.terminal || "");
    const delay = f.scheduledArrival && (f.actualArrival || f.estimatedArrival)
      ? Math.max(0, sortMin(f.actualArrival || f.estimatedArrival) - sortMin(f.scheduledArrival)) : (ride.delayMinutes || 0);
    setSaveErr("");
    setSaving(true);
    try {
      // onSave gibt jetzt das Speicher-Ergebnis zurueck ({ ok, error, cancelled? }).
      // Bei Erfolg schliesst der Parent das Formular (setEditRide(null)); scheitert
      // es, bleibt das Formular offen und die Eingabe erhalten.
      const res = await onSave({
        ...clean, ...f,
        passengerCount: pax,
        zone: toIsFestival ? f.zone : "",
        dayKey,
        estDurationMin: Number.isFinite(est) ? est : null,
        type: classify(f.fromId, f.toId, f.fromCustom, f.toCustom),
        delayMinutes: delay,
        manualOverride: flightTouched ? true : (ride.manualOverride || false),
        lastFlightUpdate: flightTouched ? Date.now() : (ride.lastFlightUpdate || null),
        flightUpdateSource: flightTouched ? "manuell" : (ride.flightUpdateSource || null),
        contactPhones: extractContactPhones(f.passengers), // aus "Name (+49…)" im Passagiere-Text
        updatedAt: Date.now(),
      });
      // cancelled = Nutzer hat den Konflikt-Dialog bewusst abgebrochen -> keine Fehlermeldung.
      if (res && res.ok === false && !res.cancelled) {
        setSaveErr(res.error || "Die Fahrt konnte nicht gespeichert werden. Bitte Verbindung prüfen und erneut versuchen.");
      }
    } catch (e) {
      console.error("RideForm.save", e);
      setSaveErr("Die Fahrt konnte nicht gespeichert werden. Bitte erneut versuchen.");
    } finally {
      setSaving(false);
    }
  };

  // Stornieren mit gleichem Schutz: Doppelklick unkritisch (idempotent), aber das
  // Formular darf bei einem Schreibfehler nicht kommentarlos schliessen.
  const doDelete = async () => {
    if (!onDelete || saving || deleting) return;
    // Slice 4: Rueckfrage vor dem Stornieren (destruktiv, ein Fehlklick storniert
    // sonst eine Fahrt). Identifikation ueber die gespeicherten Werte der Fahrt.
    const who = (ride.djName || "").trim() || "diese Fahrt";
    if (!window.confirm(`Fahrt „${who}“${ride.time ? ` um ${ride.time}` : ""} wirklich stornieren?`)) return;
    setSaveErr("");
    setDeleting(true);
    try {
      const res = await onDelete();
      if (res && res.ok === false && !res.cancelled) {
        setSaveErr(res.error || "Die Fahrt konnte nicht storniert werden. Bitte erneut versuchen.");
      }
    } catch (e) {
      console.error("RideForm.delete", e);
      setSaveErr("Die Fahrt konnte nicht storniert werden. Bitte erneut versuchen.");
    } finally {
      setDeleting(false);
    }
  };

  return (
    <Modal onClose={onClose} title={isNew ? "Neue Fahrt" : "Fahrt bearbeiten"} wide>
      <div className="grid grid-cols-2 gap-3">
        <Field label="Datum"><input type="date" className={inp} value={f.date} onChange={(e) => set("date", e.target.value)} /></Field>
        <Field label="Uhrzeit"><input type="time" className={inp} value={f.time} onChange={(e) => set("time", e.target.value)} /></Field>
        <LocSelect setup={setup} label="Von" value={f.fromId} custom={f.fromCustom}
          onId={(v) => set("fromId", v)} onCustom={(v) => set("fromCustom", v)} />
        <LocSelect setup={setup} label="Nach" value={f.toId} custom={f.toCustom}
          onId={(v) => set("toId", v)} onCustom={(v) => set("toCustom", v)} />
        {toIsFestival && (
          <Field label="Abladezone">
            <select className={inp} value={f.zone} onChange={(e) => set("zone", e.target.value)}>
              <option value="">– wählen –</option>
              {setup.zones.map((z) => <option key={z} value={z}>{z}</option>)}
            </select>
          </Field>
        )}
        <Field label="DJ / Artist"><input className={inp} value={f.djName} onChange={(e) => set("djName", e.target.value)} placeholder="z. B. Alok" /></Field>
        <Field label="Personen"><input type="number" min="1" max="8" className={inp} value={f.passengerCount} onChange={(e) => set("passengerCount", e.target.value)} /></Field>
        <Field label="Flugnummer"><input className={inp} value={f.flightNo} onChange={(e) => set("flightNo", e.target.value)} placeholder="z. B. KL1845" /></Field>
        {(f.fromId === "airport" || f.flightNo) && (
          <div className="col-span-2 rounded-xl border border-sky-500/25 bg-sky-500/5 p-3 mt-1">
            <div className="text-xs text-sky-300 font-medium mb-2 flex items-center justify-between">
              <span className="flex items-center gap-1.5"><Plane className="w-3.5 h-3.5" />Flug-Details</span>
              {ride.manualOverride && <span className="text-[10px] bg-amber-500/20 text-amber-300 px-1.5 py-0.5 rounded">manuell überschrieben</span>}
            </div>
            <div className="grid grid-cols-2 gap-2.5">
              <Field label="Airline"><input className={inp} value={f.airline} onChange={(e) => set("airline", e.target.value)} placeholder="z. B. KLM" /></Field>
              <Field label="Terminal"><input className={inp} value={f.terminal} onChange={(e) => set("terminal", e.target.value)} placeholder="z. B. Terminal 1" /></Field>
              <Field label="Geplante Ankunft"><input type="time" className={inp} value={f.scheduledArrival} onChange={(e) => set("scheduledArrival", e.target.value)} /></Field>
              <Field label="Erwartete Ankunft"><input type="time" className={inp} value={f.estimatedArrival} onChange={(e) => set("estimatedArrival", e.target.value)} /></Field>
              <Field label="Echte Ankunft"><input type="time" className={inp} value={f.actualArrival} onChange={(e) => set("actualArrival", e.target.value)} /></Field>
              <Field label="Flugstatus">
                <select className={inp} value={f.flightStatus} onChange={(e) => set("flightStatus", e.target.value)}>
                  {FLIGHT_STATUS.map((s) => <option key={s.k} value={s.k}>{s.k === "" ? "– unbekannt –" : s.l}</option>)}
                </select>
              </Field>
            </div>
            <div className="flex items-center gap-2 mt-2.5">
              <button type="button" onClick={() => fetchFlight(false)} disabled={flightBusy || !f.flightNo}
                className="text-xs bg-sky-600 hover:bg-sky-500 disabled:opacity-40 text-white px-2.5 py-1.5 rounded-lg flex items-center gap-1.5">
                <RefreshCw className={`w-3.5 h-3.5 ${flightBusy ? "animate-spin" : ""}`} />Flugstatus aktualisieren
              </button>
              {flightMsg && (
                <span className={`text-[11px] ${flightMsg.ok ? "text-emerald-400" : "text-amber-400"}`}>
                  {flightMsg.text}
                  {flightMsg.cooldown && (
                    <> · <button type="button" onClick={() => fetchFlight(true)} className="underline hover:text-emerald-300">trotzdem abfragen</button></>
                  )}
                </span>
              )}
            </div>
          </div>
        )}
        <div className="col-span-2">
          <Field label="Passagiere (Namen)"><input className={inp} value={f.passengers} onChange={(e) => set("passengers", e.target.value)} /></Field>
          {contacts.length > 0 && (
            <div className="mt-1.5 flex flex-wrap gap-1.5">
              {contacts.map((c, i) => (
                <a key={i} href={`tel:${c.phone}`} className="inline-flex items-center gap-1.5 text-xs bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 px-2 py-1 rounded-lg hover:bg-emerald-500/20">
                  <Navigation className="w-3 h-3 rotate-90" />{c.name ? `${c.name}: ` : ""}{c.phone}
                </a>
              ))}
            </div>
          )}
        </div>
        <div className="col-span-2">
          <Field label="Treffpunkt"><input className={inp} value={f.meetingPoint} onChange={(e) => set("meetingPoint", e.target.value)} placeholder="z. B. Infront of the Hotel" /></Field>
        </div>
        <div className="col-span-2">
          <Field label="Notiz (intern)"><input className={inp} value={f.notes} onChange={(e) => set("notes", e.target.value)} /></Field>
        </div>
        <div className="col-span-2">
          <Field label="Hinweis für den Gast (Artist/Manager-Link)">
            <input className={inp} value={f.guestNote} onChange={(e) => set("guestNote", e.target.value)} placeholder="z. B. Bitte Ausweis bereithalten" />
          </Field>
          <p className="text-[11px] text-stone-600 mt-1">Getrennt von der internen Notiz oben — nur dieser Text erscheint im Gast-Link.</p>
        </div>
        <label className="col-span-2 flex items-center gap-2 text-sm text-stone-300 mt-1">
          <input type="checkbox" checked={f.onDemand} onChange={(e) => set("onDemand", e.target.checked)} className="accent-orange-500 w-4 h-4" />
          Rückfahrt / on demand (Zeit flexibel)
        </label>
      </div>

      {tooBig && (
        <div className="mt-3 text-xs text-orange-300 flex items-center gap-2"><AlertTriangle className="w-3.5 h-3.5" />{pax} Personen passen in kein einzelnes Fahrzeug (V-Klasse max. 7) – ggf. auf zwei Fahrten aufteilen.</div>
      )}

      {inputWarnings.map((w, i) => (
        <div key={i} className="mt-3 text-xs text-orange-300 flex items-center gap-2"><AlertTriangle className="w-3.5 h-3.5 shrink-0" />{w}</div>
      ))}

      <div className="mt-3">
        {durKnown ? (
          <div className="text-xs text-stone-500 flex items-center gap-2">
            <Route className="w-3.5 h-3.5" />Geschätzte Fahrzeit aus Matrix: <b className="text-stone-300">{fmtDur(dur.min)}</b> · {dur.km} km
          </div>
        ) : (
          <div className="flex items-center gap-2 text-xs">
            <AlertTriangle className="w-3.5 h-3.5 text-orange-400" />
            <span className="text-orange-300">Fahrzeit für diese Strecke nicht hinterlegt – bitte manuell angeben:</span>
            <input type="number" min="1" className="w-20 bg-stone-950 border border-stone-800 rounded px-2 py-1 text-center font-mono text-xs focus:outline-none focus:border-orange-500"
              value={manualDur} onChange={(e) => setManualDur(e.target.value)} placeholder="min" />
            <span className="text-stone-500">min</span>
          </div>
        )}
      </div>

      {!isNew && ((ride.issues && ride.issues.length > 0) || (ride.log && ride.log.length > 0)) && (
        <RideHistory ride={ride} />
      )}

      {saveErr && (
        <div className="mt-4 text-sm text-red-300 bg-red-500/10 border border-red-500/25 rounded-lg px-3 py-2 flex items-center justify-between gap-3">
          <span>{saveErr}</span>
          <button onClick={save} disabled={saving || deleting} className="shrink-0 text-xs underline hover:text-red-200 disabled:opacity-40">Erneut versuchen</button>
        </div>
      )}

      <div className="flex items-center gap-2 mt-5">
        <button onClick={save} disabled={saving || deleting} className="bg-orange-600 hover:bg-orange-500 disabled:opacity-50 text-white px-4 py-2.5 rounded-lg text-sm font-medium">{saving ? "Speichere…" : "Speichern"}</button>
        <button onClick={onClose} disabled={saving || deleting} className="text-stone-400 hover:text-stone-200 disabled:opacity-40 px-4 py-2.5 text-sm">Abbrechen</button>
        {onDelete && <button onClick={doDelete} disabled={saving || deleting} className="ml-auto text-red-400 hover:text-red-300 disabled:opacity-40 text-sm flex items-center gap-1"><Ban className="w-4 h-4" />{deleting ? "Storniere…" : "Stornieren"}</button>}
      </div>
    </Modal>
  );
}

// Punkt 9: Verlauf/Audit-Log pro Fahrt + gemeldete Probleme mit Status.
const LOG_LABEL = { created: "Fahrt erstellt", assigned: "Fahrer zugeteilt", reassigned: "Fahrer geändert", time: "Uhrzeit geändert", route: "Route geändert", status: "Status geändert", problem: "Problem gemeldet", problem_progress: "Problem in Bearbeitung", problem_done: "Problem erledigt", whatsapp: "WhatsApp-Text kopiert", flight: "Flugstatus geändert" };
function RideHistory({ ride }) {
  const [open, setOpen] = useState(false);
  const log = (ride.log || []).slice().sort((a, b) => b.at - a.at);
  const issues = (ride.issues || []).slice().sort((a, b) => b.at - a.at);
  return (
    <div className="mt-4 border-t border-stone-800 pt-3">
      <button onClick={() => setOpen((o) => !o)} className="text-xs text-stone-400 hover:text-stone-200 flex items-center gap-1.5">
        <ChevronRight className={`w-3.5 h-3.5 transition ${open ? "rotate-90" : ""}`} />Verlauf &amp; Meldungen ({log.length + issues.length})
      </button>
      {open && (
        <div className="mt-2 space-y-2">
          {issues.length > 0 && (
            <div className="space-y-1">
              {issues.map((i, k) => (
                <div key={k} className="text-xs flex items-center gap-2 bg-stone-950/50 rounded px-2 py-1">
                  <span className={`px-1.5 py-0.5 rounded text-[10px] ${i.state === "done" ? "bg-emerald-500/20 text-emerald-300" : i.state === "progress" ? "bg-amber-500/20 text-amber-300" : "bg-red-500/20 text-red-300"}`}>{ISSUE_STATE_LABEL[i.state] || "offen"}</span>
                  <span className="text-stone-300">{i.type}{i.note ? `: ${i.note}` : ""}</span>
                  <span className="text-stone-600 ml-auto">{fmtClock(i.at)}</span>
                </div>
              ))}
            </div>
          )}
          <div className="space-y-0.5 max-h-40 overflow-y-auto">
            {log.map((e, k) => (
              <div key={k} className="text-[11px] flex items-center gap-2 text-stone-500">
                <span className="font-mono text-stone-600 shrink-0">{fmtClock(e.at)}</span>
                <span className="text-stone-300">{LOG_LABEL[e.event] || e.event}</span>
                {e.detail && <span className="text-stone-500 truncate">· {e.detail}</span>}
                <span className="text-stone-700 ml-auto shrink-0">{e.by}</span>
              </div>
            ))}
            {log.length === 0 && <div className="text-[11px] text-stone-600">Noch keine Einträge.</div>}
          </div>
        </div>
      )}
    </div>
  );
}

function LocSelect({ setup, label, value, custom, onId, onCustom }) {
  return (
    <Field label={label}>
      <select className={inp} value={value} onChange={(e) => onId(e.target.value)}>
        {setup.locations.map((l) => <option key={l.id} value={l.id}>{l.short}</option>)}
        <option value="__custom">Anderer Ort…</option>
      </select>
      {value === "__custom" && <input className={inp + " mt-1.5"} value={custom} onChange={(e) => onCustom(e.target.value)} placeholder="Ort eingeben" />}
    </Field>
  );
}

/* -------- Mission-Control-Variante der Fahrer-Uebersicht (Session 8, Teil 1) --
 * Eigenstaendige Kopie von DriversTab, nur fuer uiMode === "mission-control".
 * DATENABLEITUNG + SORTIERUNG SIND VERBATIM aus DriversTab uebernommen
 * (computeDriverStats, maxMin, live, freeCount/busyCount, Sortierregel). Es wird
 * KEINE Fahrer-, Status-, Rollen-, Zuteilungs- oder GPS-SCHREIBLOGIK veraendert.
 * Neu ist ausschliesslich der Render (MC-Design). Online/Offline + letzter
 * Kontakt werden NUR GELESEN aus driverState[id].gps mit derselben Frische-Regel
 * wie die Live-Karte (GPS_MAX_AGE_MS, fmtAgo) - exakt wie an den bestehenden
 * Lesestellen. Der aktuelle Auftrag ist die von computeDriverStats ohnehin schon
 * berechnete laufende Fahrt (s.active), nur bisher nicht angezeigt. Classic
 * DriversTab bleibt byte-genau unveraendert. */
function MissionDriversTab({ setup, dyn, day }) {
  const [, setTick] = useState(0);
  useEffect(() => { const t = setInterval(() => setTick((x) => x + 1), 30000); return () => clearInterval(t); }, []);

  // ---- Datenableitung: VERBATIM aus DriversTab (keine Logikaenderung) ----
  const rows = setup.drivers.map((d) => ({ d, s: computeDriverStats(setup, dyn, d.id, day) }));
  const maxMin = Math.max(1, ...rows.map((r) => r.s.drivingMin));
  const now = dayNowMin(day);
  const live = now >= 0 && now < 90000;
  const ln = (id) => setup.locations.find((l) => l.id === id)?.short || null;
  const freeCount = rows.filter((r) => r.s.availability === "free").length;
  const busyCount = rows.length - freeCount;
  const sorted = rows.slice().sort((a, b) => {
    // Beim Zuteilen sind freie Fahrer am interessantesten -> zuerst die freien
    // (nach geringster Auslastung), dann die belegten. (identisch zu DriversTab)
    if (live && a.s.availability !== b.s.availability) return a.s.availability === "free" ? -1 : 1;
    if (live && a.s.availability === "free" && b.s.availability === "free") return a.s.drivingMin - b.s.drivingMin;
    return b.s.drivingMin - a.s.drivingMin;
  });

  // ---- rein PRAESENTATIONAL (neu, keine Logikaenderung) ----
  // Online/letzter Kontakt: nur Lesen, gleiche Frische-Regel wie die Live-Karte.
  const gpsInfo = (id) => {
    const fix = dyn.driverState?.[id]?.gps;
    if (!fix || fix.at == null) return { has: false, online: false, ago: null };
    return { has: true, online: (Date.now() - fix.at) <= GPS_MAX_AGE_MS, ago: fmtAgo(fix.at) };
  };
  // Aktueller Auftrag = laufende Fahrt (s.active): Zeit + Route, reine Anzeige.
  const activeRoute = (r) => r ? { time: r.time, from: ln(r.fromId) || r.fromCustom || "?", to: ln(r.toId) || r.toCustom || "?" } : null;

  if (!setup.drivers.length) {
    return (
      <div className="mc-scope">
        <MissionPanel icon={Users} title="Fahrer" subtitle={`Auslastung ${fmtDate(day)}`}>
          <EmptyState icon={Users} title="Keine Fahrer geladen"
            hint="Sobald Fahrer in den Stammdaten stehen, erscheinen sie hier mit Status, Auslastung und Live-Kontakt." />
        </MissionPanel>
      </div>
    );
  }

  return (
    <div className="mc-scope space-y-3">
      <MissionPanel
        icon={Users}
        title="Fahrer"
        subtitle={`Auslastung ${fmtDate(day)} · gleichmäßiger Einsatz`}
        actions={live ? (
          <div className="flex items-center gap-2">
            <StatusBadge status="done" label={`${freeCount} frei`} />
            <StatusBadge status="enroute" label={`${busyCount} auf Fahrt`} />
          </div>
        ) : null}
      >
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-2">
          {sorted.map(({ d, s }) => {
            const loc = live ? ln(s.locNow) : null;
            const freeAtTxt = live && s.availability === "busy" && s.freeAt != null ? fromMin(s.freeAt) : null;
            const overload = s.drivingMin >= setup.config.softHoursMin;
            const gi = gpsInfo(d.id);
            const ar = live ? activeRoute(s.active) : null;
            const pct = Math.round((s.drivingMin / maxMin) * 100);
            const isVan = d.vehicleType === "Van";
            return (
              <div key={d.id} className="mc-ride-card" style={{ padding: "12px 14px" }}>
                {/* Kopf: Fahrzeug + Name + Online + Status */}
                <div className="flex items-center gap-3">
                  <span className="inline-flex items-center gap-1 text-[11px] font-mono px-1.5 py-0.5 rounded shrink-0"
                    style={{ background: isVan ? "var(--mc-st-assigned-soft)" : "var(--mc-st-new-soft)", color: isVan ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }}>
                    <Car className="w-3 h-3" />{isVan ? "Van" : "Car"}
                  </span>
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2">
                      <span className="text-sm font-semibold truncate" style={{ color: "var(--mc-text)" }}>{d.firstName} {d.lastName}</span>
                      {gi.has && (
                        <span className="inline-flex items-center gap-1 text-[10px] shrink-0"
                          style={{ color: gi.online ? "var(--mc-st-done)" : "var(--mc-text-muted)" }}>
                          {gi.online ? <Wifi className="w-3 h-3" /> : <WifiOff className="w-3 h-3" />}
                          {gi.online ? "Online" : "Offline"}
                        </span>
                      )}
                    </div>
                    {gi.has && (
                      <div className="text-[10px] mt-0.5" style={{ color: "var(--mc-text-muted)" }}>letzter Kontakt {gi.ago}</div>
                    )}
                  </div>
                  {live && (
                    s.availability === "free"
                      ? <StatusBadge status="done" label={`Frei${loc ? ` · ${loc}` : ""}`} />
                      : <StatusBadge status="enroute" label={`Auf Fahrt${freeAtTxt ? ` · frei ${freeAtTxt}` : ""}`} />
                  )}
                </div>

                {/* Aktueller Auftrag (laufende Fahrt) */}
                {ar && (
                  <div className="mt-2 flex items-center gap-1.5 text-xs rounded-md px-2 py-1"
                    style={{ background: "var(--mc-inset)", color: "var(--mc-text-secondary)" }}>
                    <Navigation className="w-3.5 h-3.5 shrink-0" style={{ color: "var(--mc-st-enroute)" }} />
                    <span className="font-mono shrink-0" style={{ color: "var(--mc-text)" }}>{ar.time}</span>
                    <span className="truncate">{ar.from}</span>
                    <ArrowRight className="w-3 h-3 shrink-0" />
                    <span className="truncate">{ar.to}</span>
                  </div>
                )}

                {/* Auslastung: Balken + Fahrten-Count + Fahrzeit */}
                <div className="mt-2 flex items-center gap-3">
                  <div className="flex-1" style={{ height: 6, borderRadius: 999, background: "var(--mc-inset)", overflow: "hidden" }}>
                    <div style={{ height: "100%", width: `${pct}%`, borderRadius: 999, background: overload ? "var(--mc-st-problem)" : "var(--mc-st-assigned)" }} />
                  </div>
                  <span className="text-xs font-mono shrink-0" style={{ color: "var(--mc-text-secondary)" }}>{s.count}×</span>
                  <span className="text-xs font-mono shrink-0 inline-flex items-center gap-1"
                    style={{ color: overload ? "var(--mc-st-problem)" : "var(--mc-text-secondary)" }}>
                    <Gauge className="w-3.5 h-3.5" />{fmtDur(s.drivingMin)}
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      </MissionPanel>
    </div>
  );
}

/* -------- Punkt 5: WhatsApp-Texte (nur generieren + kopieren) ------------- */
function waLoc(setup, id, custom) { return setup.locations.find((l) => l.id === id)?.name || custom || "—"; }
function waDriverText(setup, ride) {
  const drv = setup.drivers.find((d) => d.id === ride.assignedDriverId);
  return [
    "Neue Shuttle-Fahrt:",
    `Zeit: ${ride.time}`,
    `Route: ${waLoc(setup, ride.fromId, ride.fromCustom)} → ${waLoc(setup, ride.toId, ride.toCustom)}${ride.zone ? ` (${ride.zone})` : ""}`,
    ride.djName ? `Artist/Gast: ${ride.djName}` : null,
    `Personen: ${ride.passengerCount}`,
    ride.meetingPoint ? `Treffpunkt: ${ride.meetingPoint}` : null,
    ride.flightNo ? `Flug: ${ride.flightNo}${ride.flightStatus ? ` (${flightStyle(ride.flightStatus).l})` : ""}` : null,
    ride.notes ? `Notiz: ${ride.notes}` : null,
    drv ? `Fahrzeug: ${drv.vehicleType === "Van" ? "Van" : "Car"}` : null,
    "Bitte bestätigen.",
  ].filter(Boolean).join("\n");
}
function waArtistText(setup, ride) {
  const drv = setup.drivers.find((d) => d.id === ride.assignedDriverId);
  const veh = drv ? (drv.vehicleType === "Van" ? "Van" : "Car") : null;
  return [
    "Your shuttle is confirmed.",
    `Pickup time: ${ride.time}`,
    `Pickup location: ${waLoc(setup, ride.fromId, ride.fromCustom)}${ride.meetingPoint ? `, ${ride.meetingPoint}` : ""}`,
    drv ? `Driver: ${drv.firstName}${drv.phone ? ` (${drv.phone})` : ""}` : null,
    veh ? `Vehicle: ${veh}` : null,
    `Destination: ${waLoc(setup, ride.toId, ride.toCustom)}${ride.zone ? ` – ${ride.zone}` : ""}`,
    "If anything changes, please contact us.",
  ].filter(Boolean).join("\n");
}
async function copyText(text) {
  try { await navigator.clipboard.writeText(text); return true; }
  catch {
    try {
      const ta = document.createElement("textarea"); ta.value = text; ta.style.position = "fixed"; ta.style.opacity = "0";
      document.body.appendChild(ta); ta.focus(); ta.select(); const ok = document.execCommand("copy"); document.body.removeChild(ta); return ok;
    } catch { return false; }
  }
}
function WhatsAppModal({ ride, setup, onClose, onCopied }) {
  const driverTxt = waDriverText(setup, ride);
  const artistTxt = waArtistText(setup, ride);
  const [copied, setCopied] = useState(null);
  const doCopy = async (which, txt) => { const ok = await copyText(txt); if (ok) { setCopied(which); onCopied?.(which === "driver" ? "Fahrer-Text" : "Artist-Text"); setTimeout(() => setCopied(null), 1800); } };
  const Block = ({ id, title, txt }) => (
    <div className="rounded-xl border border-stone-800 bg-stone-950 p-3">
      <div className="flex items-center justify-between mb-2">
        <span className="text-xs font-medium text-stone-300">{title}</span>
        <button onClick={() => doCopy(id, txt)} className="text-xs bg-emerald-600 hover:bg-emerald-500 text-white px-2.5 py-1 rounded-lg flex items-center gap-1.5">
          {copied === id ? <><Check className="w-3.5 h-3.5" />kopiert</> : <><Copy className="w-3.5 h-3.5" />Text kopieren</>}
        </button>
      </div>
      <pre className="text-xs text-stone-300 whitespace-pre-wrap font-sans leading-relaxed">{txt}</pre>
    </div>
  );
  return (
    <Modal onClose={onClose} title="WhatsApp-Texte" wide>
      <div className="text-xs text-stone-500 mb-3">{ride.time} · {waLoc(setup, ride.fromId, ride.fromCustom)} → {waLoc(setup, ride.toId, ride.toCustom)}{ride.djName && <> · <span className="text-orange-300 font-medium">{ride.djName}</span></>}</div>
      <div className="space-y-3">
        <Block id="driver" title="Für den Fahrer (Deutsch)" txt={driverTxt} />
        <Block id="artist" title="Für Artist / Manager (English)" txt={artistTxt} />
      </div>
      <p className="text-[11px] text-stone-600 mt-3">Texte werden nur kopiert – nichts wird automatisch gesendet.</p>
    </Modal>
  );
}

/* -------- Fahrer-Telefonnummern (für Anruf/Weitergabe an Manager) --------- */
// Weiche Telefon-Plausibilitaetspruefung fuer Eingabefelder: true, wenn etwas
// eingetragen ist, das NICHT wie eine Telefonnummer aussieht. Leer gilt als ok
// (Felder sind optional). Trennzeichen (Leerzeichen, - / . ( )) werden ignoriert,
// danach muessen es +? und 6-15 Ziffern sein (gleiche Regel wie extractContactPhones).
// Bewusst weich: nur ein Hinweis, blockiert nie das Speichern.
function phoneLooksInvalid(raw) {
  const s = String(raw || "").trim();
  if (!s) return false;
  const cleaned = s.replace(/[\s\-\/().]/g, "");
  return !/^\+?[0-9]{6,15}$/.test(cleaned);
}
function DriverPhones({ setup, updateSetup }) {
  const [phones, setPhones] = useState(() => Object.fromEntries(setup.drivers.map((d) => [d.id, d.phone || ""])));
  const [plates, setPlates] = useState(() => Object.fromEntries(setup.drivers.map((d) => [d.id, d.plate || ""])));
  const [pins, setPins] = useState(() => Object.fromEntries(setup.drivers.map((d) => [d.id, d.pin || ""])));
  const [saved, setSaved] = useState(false);
  const [saveError, setSaveError] = useState("");
  const dirty = setup.drivers.some((d) => (phones[d.id] || "") !== (d.phone || "") || (plates[d.id] || "") !== (d.plate || "") || (pins[d.id] || "") !== (d.pin || ""));
  // Slice 3: weicher Hinweis auf ungewoehnliche Nummern (blockiert NICHT). Formate
  // variieren (Auslandsvorwahlen etc.), daher nur ein Hinweis, kein Speicherblocker.
  const oddPhones = setup.drivers.filter((d) => phoneLooksInvalid(phones[d.id])).map((d) => `${d.firstName} ${d.lastName[0]}.`);
  const save = async () => {
    setSaveError("");
    // "gespeichert" nur zeigen, wenn updateSetup wirklich ok meldet. Sonst
    // sähe der Nutzer eine Erfolgsmeldung, obwohl Telefonnummer/Kennzeichen/PIN
    // nie in der DB gelandet sind.
    const res = await updateSetup((s) => { s.drivers.forEach((d) => { d.phone = (phones[d.id] || "").trim(); d.plate = (plates[d.id] || "").trim(); d.pin = (pins[d.id] || "").trim(); }); return s; });
    if (res && res.ok) { setSaved(true); setTimeout(() => setSaved(false), 1800); }
    else setSaveError(res?.error || "Speichern fehlgeschlagen, bitte erneut versuchen.");
  };
  return (
    <div>
      <h3 className="font-medium text-stone-200 mb-1 flex items-center gap-2"><Radio className="w-4 h-4" />Fahrer-Telefonnummern, Kennzeichen &amp; PIN</h3>
      <p className="text-xs text-stone-500 mb-3">Telefonnummer für Anruf-Buttons in der Leitstelle. Kennzeichen optional — erscheint nur, wenn gepflegt, im Gast-/Artist-Link. Eigener PIN optional — leer lassen, um den Standard-PIN (unten bei „Zugangs-PINs") zu nutzen. Alles bleibt im System (im Deployment in der DB, nicht im Code).</p>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-4 gap-y-1.5 max-h-72 overflow-y-auto pr-1">
        {setup.drivers.map((d) => (
          <div key={d.id} className="flex items-center gap-1.5 text-sm flex-wrap">
            <span className={`text-[10px] font-mono px-1.5 py-0.5 rounded shrink-0 w-12 text-center ${d.vehicleType === "Van" ? "bg-orange-500/20 text-orange-300" : "bg-sky-500/20 text-sky-300"}`}>{d.vehicleType === "Van" ? "Van" : "Car"}</span>
            <span className="text-stone-400 w-20 truncate shrink-0">{d.firstName} {d.lastName[0]}.</span>
            <input type="tel" className="flex-1 min-w-0 bg-stone-950 border border-stone-800 rounded px-2 py-1 text-sm text-stone-200 placeholder-stone-600 focus:outline-none focus:border-orange-500"
              value={phones[d.id] || ""} onChange={(e) => setPhones((p) => ({ ...p, [d.id]: e.target.value }))} placeholder="+49 …" />
            <input className="w-16 shrink-0 bg-stone-950 border border-stone-800 rounded px-2 py-1 text-sm text-stone-200 placeholder-stone-600 focus:outline-none focus:border-orange-500"
              value={plates[d.id] || ""} onChange={(e) => setPlates((p) => ({ ...p, [d.id]: e.target.value }))} placeholder="Kennz." />
            <input className="w-16 shrink-0 bg-stone-950 border border-stone-800 rounded px-2 py-1 text-sm text-stone-200 placeholder-stone-600 focus:outline-none focus:border-orange-500"
              value={pins[d.id] || ""} onChange={(e) => setPins((p) => ({ ...p, [d.id]: e.target.value.replace(/\D/g, "") }))} placeholder="PIN" inputMode="numeric" />
          </div>
        ))}
      </div>
      <div className="flex items-center gap-2 mt-3">
        <button onClick={save} disabled={!dirty} className="bg-orange-600 hover:bg-orange-500 disabled:opacity-40 text-white text-sm px-3 py-2 rounded-lg">Speichern</button>
        {saved && <span className="text-xs text-emerald-400 flex items-center gap-1"><Check className="w-3.5 h-3.5" />gespeichert</span>}
        {saveError && <span className="text-xs text-red-400">{saveError}</span>}
      </div>
      {oddPhones.length > 0 && (
        <div className="text-xs text-amber-300 mt-2">{oddPhones.length} Nummer(n) sehen ungewöhnlich aus ({oddPhones.slice(0, 4).join(", ")}{oddPhones.length > 4 ? " …" : ""}), bitte prüfen. Speichern geht trotzdem.</div>
      )}
    </div>
  );
}

/* -------- Leitstellen-Nutzer (für namentliche Zuordnung im Protokoll) ----- */
function DispatcherUsers({ setup, updateSetup }) {
  const [names, setNames] = useState(() => Object.fromEntries((setup.dispatchers || []).map((p) => [p.id, p.name])));
  const [pins, setPins] = useState(() => Object.fromEntries((setup.dispatchers || []).map((p) => [p.id, p.pin || ""])));
  const [saved, setSaved] = useState(false);
  const [saveError, setSaveError] = useState("");
  const dirty = (setup.dispatchers || []).some((p) => (names[p.id] || "") !== p.name || (pins[p.id] || "") !== (p.pin || ""));
  const save = async () => {
    setSaveError("");
    const res = await updateSetup((s) => { (s.dispatchers || []).forEach((p) => { p.name = (names[p.id] || p.name).trim(); p.pin = (pins[p.id] || "").trim(); }); return s; });
    if (res && res.ok) { setSaved(true); setTimeout(() => setSaved(false), 1800); }
    else setSaveError(res?.error || "Speichern fehlgeschlagen, bitte erneut versuchen.");
  };
  const addOne = async () => {
    const name = window.prompt("Name des neuen Leitstellen-Nutzers?");
    if (!name || !name.trim()) return;
    setSaveError("");
    const res = await updateSetup((s) => { s.dispatchers = [...(s.dispatchers || []), { id: slug(name.trim()) + "-" + Date.now().toString(36).slice(-3), name: name.trim(), pin: "" }]; return s; });
    if (!(res && res.ok)) setSaveError(res?.error || "Hinzufügen fehlgeschlagen, bitte erneut versuchen.");
  };
  return (
    <div>
      <h3 className="font-medium text-stone-200 mb-1 flex items-center gap-2"><Users className="w-4 h-4" />Leitstellen-Nutzer</h3>
      <p className="text-xs text-stone-500 mb-3">Wer sich hier anmeldet, erscheint namentlich statt anonym „Leitstelle" im Änderungsprotokoll. Eigener PIN optional — leer lassen, um den Standard-PIN (unten bei „Zugangs-PINs") zu nutzen.</p>
      <div className="space-y-1.5">
        {(setup.dispatchers || []).map((p) => (
          <div key={p.id} className="flex items-center gap-2 text-sm">
            <input className="flex-1 bg-stone-950 border border-stone-800 rounded px-2 py-1.5 text-sm text-stone-200 focus:outline-none focus:border-orange-500"
              value={names[p.id] ?? p.name} onChange={(e) => setNames((n) => ({ ...n, [p.id]: e.target.value }))} />
            <input className="w-20 shrink-0 bg-stone-950 border border-stone-800 rounded px-2 py-1.5 text-sm text-stone-200 placeholder-stone-600 focus:outline-none focus:border-orange-500"
              value={pins[p.id] || ""} onChange={(e) => setPins((n) => ({ ...n, [p.id]: e.target.value.replace(/\D/g, "") }))} placeholder="PIN" inputMode="numeric" />
          </div>
        ))}
      </div>
      <div className="flex items-center gap-2 mt-3">
        <button onClick={save} disabled={!dirty} className="bg-orange-600 hover:bg-orange-500 disabled:opacity-40 text-white text-sm px-3 py-2 rounded-lg">Speichern</button>
        <button onClick={addOne} className="text-sm bg-stone-800 hover:bg-stone-700 text-stone-200 px-3 py-2 rounded-lg flex items-center gap-1.5"><Plus className="w-3.5 h-3.5" />Person hinzufügen</button>
        {saved && <span className="text-xs text-emerald-400 flex items-center gap-1"><Check className="w-3.5 h-3.5" />gespeichert</span>}
        {saveError && <span className="text-xs text-red-400">{saveError}</span>}
      </div>
    </div>
  );
}

